  const totalOutstanding = unpaidBills.reduce((acc, b) => acc + b.amount, 0);

  useEffect(() => {
    const fetchSummary = async () => {
      if (unpaidBills.length > 0) {
        setIsLoadingSummary(true);
        const summary = await getAdminBriefing(unpaidBills);
        setAiSummary(summary);
        setIsLoadingSummary(false);
      }
    };
    fetchSummary();
  }, []);

  const selectedProperty = properties.find(p => p.id === selectedPropertyId);
  const filteredBills = selectedPropertyId 
    ? bills.filter(b => b.propertyId === selectedPropertyId)
    : bills;

  return (
    <div className="space-y-8 animate-fadeIn">
      <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
        <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-100 flex items-center gap-4">
          <div className="bg-blue-100 p-3 rounded-xl">
            <i className="fas fa-building text-blue-600 text-2xl"></i>
          </div>
          <div>
            <p className="text-sm text-slate-500 font-medium">Total Properties</p>
            <p className="text-2xl font-bold text-slate-800">{properties.length}</p>
          </div>
        </div>
        <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-100 flex items-center gap-4">
          <div className="bg-amber-100 p-3 rounded-xl">
            <i className="fas fa-clock text-amber-600 text-2xl"></i>
          </div>
          <div>
            <p className="text-sm text-slate-500 font-medium">Pending Bills</p>
            <p className="text-2xl font-bold text-slate-800">{unpaidBills.length}</p>
          </div>
        </div>
        <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-100 flex items-center gap-4">
          <div className="bg-emerald-100 p-3 rounded-xl">
            <i className="fas fa-dollar-sign text-emerald-600 text-2xl"></i>
          </div>
          <div>
            <p className="text-sm text-slate-500 font-medium">Total Outstanding</p>
            <p className="text-2xl font-bold text-slate-800">${totalOutstanding.toFixed(2)}</p>
