                      <td className="px-6 py-4">
                        <span className="text-sm font-bold text-slate-800">${bill.amount.toFixed(2)}</span>
                      </td>
                      <td className="px-6 py-4">
                        <span className={`px-2.5 py-1 rounded-full text-xs font-bold ${
                          bill.status === BillStatus.PAID 
                            ? 'bg-emerald-100 text-emerald-700' 
                            : 'bg-rose-100 text-rose-700'
                        }`}>
                          {bill.status}
                        </span>
                      </td>
                      <td className="px-6 py-4 text-right">
                        <button
                          onClick={() => onUpdateStatus(bill.id, bill.status === BillStatus.PAID ? BillStatus.UNPAID : BillStatus.PAID)}
                          className={`text-xs font-bold py-1.5 px-3 rounded-lg border transition-all ${
                            bill.status === BillStatus.PAID
                              ? 'text-rose-600 border-rose-200 hover:bg-rose-50'
                              : 'text-emerald-600 border-emerald-200 hover:bg-emerald-50'
