import React, { useState, useEffect } from 'react';
import Layout from './components/Layout';
import AdminView from './components/AdminView';
import OwnerView from './components/OwnerView';
import { User, Property, Bill, BillStatus, MOCK_USERS, MOCK_PROPERTIES, MOCK_BILLS } from './types';
import { MOCK_USERS as users, MOCK_PROPERTIES as props, MOCK_BILLS as billsData } from './services/mockData';

const App: React.FC = () => {
  const [user, setUser] = useState<User | null>(null);
  const [properties, setProperties] = useState<Property[]>(props);
  const [bills, setBills] = useState<Bill[]>(billsData);
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [error, setError] = useState('');

  const handleLogin = (e: React.FormEvent) => {
    e.preventDefault();
    const foundUser = users.find(u => u.email === email);
    if (foundUser) {
      setUser(foundUser);
      setError('');
    } else {
      setError('Invalid credentials. Try admin@electra.com or john@example.com');
