import React, { useState } from 'react';
import Layout from './components/Layout';
import SuperAdminView from './components/SuperAdminView';
import AdminView from './components/AdminView';
import { User, Property, Bill, BillStatus } from './types';
import { authService } from './services/authService';
import { MOCK_PROPERTIES as props, MOCK_BILLS as billsData, MOCK_USERS } from './services/mockData';

const App: React.FC = () => {
  const [user, setUser] = useState<User | null>(null);
  const [properties, setProperties] = useState<Property[]>(props);
  const [bills, setBills] = useState<Bill[]>(billsData);
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [error, setError] = useState('');
  const [isLoggingIn, setIsLoggingIn] = useState(false);
  const [showDemoTools, setShowDemoTools] = useState(false);

  const handleLogin = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsLoggingIn(true);
    setError('');

    try {
      const authenticatedUser = await authService.login(email, password);
      setUser(authenticatedUser);
    } catch (err: any) {
      setError(err.message || 'An error occurred during login');
    } finally {
      setIsLoggingIn(false);
    }
  };

  const handleLogout = () => {
    setUser(null);
    setEmail('');
    setPassword('');
    setError('');
  };

  const handleAddProperty = (name: string, address: string) => {
    const newProperty: Property = {
      id: `p${properties.length + 1}`,
      name,
      address,
      totalPendingAmount: 0
    };
    setProperties([...properties, newProperty]);
  };

  const updateBillStatus = (billId: string, newStatus: BillStatus) => {
    setBills(prev => prev.map(b => b.id === billId ? { ...b, status: newStatus } : b));
  };

  const fillDemoCredentials = (role: 'SUPER_ADMIN' | 'ADMIN') => {
    const demoUser = MOCK_USERS.find(u => u.role === role);
    if (demoUser) {
      setEmail(demoUser.email);
      setPassword(demoUser.password || 'password123');
      setShowDemoTools(false);
    }
  };

  if (!user) {
    return (
      <div className="min-h-screen flex items-center justify-center bg-slate-50 px-4 relative overflow-hidden font-sans">
        <div className="absolute inset-0 z-0 pointer-events-none opacity-30">
          <div className="absolute top-0 right-0 w-[500px] h-[500px] bg-indigo-200 rounded-full blur-[120px] -mr-64 -mt-64"></div>
          <div className="absolute bottom-0 left-0 w-[500px] h-[500px] bg-emerald-100 rounded-full blur-[120px] -ml-64 -mb-64"></div>
        </div>

        <div className="max-w-md w-full bg-white/80 backdrop-blur-xl rounded-[40px] shadow-2xl p-10 border border-white/50 relative z-10">
          <div className="flex flex-col items-center mb-10 text-center">
            <div className="w-20 h-20 bg-gradient-to-br from-indigo-600 to-indigo-700 rounded-3xl mb-6 shadow-xl shadow-indigo-100 flex items-center justify-center">
              <i className="fas fa-bolt text-white text-4xl"></i>
            </div>
            <h1 className="text-3xl font-black text-slate-800 tracking-tight">ElectraFlow</h1>
            <p className="text-slate-400 mt-2 font-semibold uppercase tracking-widest text-[10px]">Management Enterprise</p>
          </div>

          <form onSubmit={handleLogin} className="space-y-6">
            <div className="space-y-2">
              <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest px-1">Identity (Email)</label>
              <input 
                type="email" 
                value={email}
                onChange={(e) => setEmail(e.target.value)}
                placeholder="identity@electra.com"
                className="w-full px-6 py-4 bg-slate-50 border border-slate-100 rounded-2xl focus:ring-2 focus:ring-indigo-500 outline-none transition-all font-medium text-slate-700"
                required 
              />
            </div>
            <div className="space-y-2">
              <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest px-1">Access Key (Password)</label>
              <input 
                type="password" 
                value={password}
                onChange={(e) => setPassword(e.target.value)}
                placeholder="••••••••"
                className="w-full px-6 py-4 bg-slate-50 border border-slate-100 rounded-2xl focus:ring-2 focus:ring-indigo-500 outline-none transition-all font-medium text-slate-700"
                required 
              />
            </div>

            {error && (
              <div className="p-4 bg-rose-50 text-rose-600 text-xs font-bold rounded-2xl border border-rose-100 animate-shake">
                {error}
              </div>
            )}

            <button 
              type="submit" 
              disabled={isLoggingIn}
              className="w-full bg-slate-800 hover:bg-slate-900 text-white font-black py-5 rounded-[22px] shadow-2xl transition-all active:scale-[0.98] disabled:opacity-50"
            >
              {isLoggingIn ? 'Verifying Access...' : 'Authenticate'}
            </button>
          </form>

          <button 
            onClick={() => setShowDemoTools(!showDemoTools)}
            className="mt-10 w-full text-[10px] font-black text-slate-300 hover:text-indigo-400 uppercase tracking-widest transition-colors"
          >
            Switch System Profile
          </button>

          {showDemoTools && (
            <div className="mt-6 grid grid-cols-2 gap-3 animate-fadeIn">
              <button onClick={() => fillDemoCredentials('SUPER_ADMIN')} className="p-4 bg-indigo-50 text-indigo-600 rounded-2xl border border-indigo-100 text-[10px] font-black uppercase">Super Admin</button>
              <button onClick={() => fillDemoCredentials('ADMIN')} className="p-4 bg-emerald-50 text-emerald-600 rounded-2xl border border-emerald-100 text-[10px] font-black uppercase">Staff Admin</button>
            </div>
          )}
        </div>

        <style dangerouslySetInnerHTML={{ __html: `
          @keyframes shake { 0%, 100% { transform: translateX(0); } 25% { transform: translateX(-4px); } 75% { transform: translateX(4px); } }
          .animate-shake { animation: shake 0.2s ease-in-out 0s 2; }
          .animate-fadeIn { animation: fadeIn 0.4s ease-out; }
          .animate-scaleUp { animation: scaleUp 0.3s cubic-bezier(0.34, 1.56, 0.64, 1); }
          @keyframes fadeIn { from { opacity: 0; transform: translateY(10px); } to { opacity: 1; transform: translateY(0); } }
          @keyframes scaleUp { from { opacity: 0; transform: scale(0.9); } to { opacity: 1; transform: scale(1); } }
        `}} />
      </div>
    );
  }

  return (
    <Layout user={user} onLogout={handleLogout}>
      {user.role === 'SUPER_ADMIN' ? (
        <SuperAdminView 
          properties={properties} 
          bills={bills}
          onAddProperty={handleAddProperty}
        />
      ) : (
        <AdminView 
          properties={properties} 
          bills={bills} 
          onUpdateStatus={updateBillStatus} 
        />
      )}
    </Layout>
  );
};

