import React, { useState, useMemo } from 'react';
import { Property, Bill, BillStatus } from '../types';
import PropertyDetails from './PropertyDetails';

interface AdminViewProps {
  properties: Property[];
  bills: Bill[];
  onUpdateStatus: (billId: string, newStatus: BillStatus) => void;
}

const AdminView: React.FC<AdminViewProps> = ({ properties, bills, onUpdateStatus }) => {
  const [selectedPropertyId, setSelectedPropertyId] = useState<string | null>(null);
  const [searchQuery, setSearchQuery] = useState('');

  // Generate the last 6 months for the status grid
  const lastSixMonths = useMemo(() => {
    const months = [];
    const date = new Date();
    const monthNames = ["January", "February", "March", "April", "May", "June", "July", "August", "September", "October", "November", "December"];

    for (let i = 0; i < 6; i++) {
      const d = new Date(date.getFullYear(), date.getMonth() - i, 1);
      months.push(`${monthNames[d.getMonth()]} ${d.getFullYear()}`);
    }
    return months; // Most recent first
  }, []);

  const currentMonth = lastSixMonths[0];

  const filteredProperties = properties.filter(p => 
    p.name.toLowerCase().includes(searchQuery.toLowerCase()) || 
    p.address.toLowerCase().includes(searchQuery.toLowerCase())
  );

  return (
    <div className="space-y-8 animate-fadeIn pb-20">
      <div className="flex flex-col md:flex-row justify-between items-start md:items-end gap-6">
        <div>
          <h1 className="text-3xl font-black text-slate-800 tracking-tight">Status Operations</h1>
          <p className="text-slate-500 text-sm">Review and update payment statuses across the last 6 months</p>
        </div>

        <div className="relative w-full md:w-80">
          <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1.5 ml-1">Search Property</label>
          <div className="relative">
            <i className="fas fa-search absolute left-4 top-1/2 -translate-y-1/2 text-slate-400 text-sm"></i>
            <input 
              type="text"
              placeholder="Name or address..."
              value={searchQuery}
              onChange={e => setSearchQuery(e.target.value)}
              className="w-full pl-11 pr-4 py-3 bg-white border border-slate-200 rounded-xl shadow-sm focus:ring-2 focus:ring-emerald-500 outline-none font-medium"
            />
          </div>
        </div>
      </div>

      <div className="bg-white rounded-[2rem] border border-slate-100 shadow-xl overflow-hidden">
        <div className="p-6 border-b border-slate-50 bg-slate-50/50 flex justify-between items-center">
          <h3 className="font-bold text-slate-800 flex items-center gap-2">
            <i className="fas fa-calendar-check text-emerald-500"></i>
            6-Month Payment Grid
          </h3>
          <div className="flex gap-2">
            <span className="flex items-center gap-1 text-[10px] font-bold text-emerald-600"><span className="w-2 h-2 rounded-full bg-emerald-500"></span> Paid</span>
            <span className="flex items-center gap-1 text-[10px] font-bold text-rose-600"><span className="w-2 h-2 rounded-full bg-rose-500"></span> Unpaid</span>
          </div>
        </div>
        <div className="overflow-x-auto">
          <table className="w-full text-left">
            <thead>
              <tr className="text-[10px] font-black text-slate-400 uppercase tracking-widest bg-slate-50/30">
                <th className="px-8 py-5 min-w-[200px]">Property</th>
                <th className="px-4 py-5 text-center bg-emerald-50/30">{currentMonth} (Current)</th>
                {lastSixMonths.slice(1).map(month => (
                  <th key={month} className="px-4 py-5 text-center font-medium opacity-60">{month}</th>
                ))}
                <th className="px-8 py-5 text-right">Action</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-50">
              {filteredProperties.length === 0 ? (
                <tr>
                  <td colSpan={8} className="px-8 py-20 text-center text-slate-400 font-medium italic">
                    No properties found matching your search.
                  </td>
                </tr>
              ) : filteredProperties.map(p => {
                const propertyBills = bills.filter(b => b.propertyId === p.id);
                const currentBill = propertyBills.find(b => b.month === currentMonth);

                return (
                  <tr key={p.id} className="group hover:bg-slate-50 transition-all">
                    <td className="px-8 py-6 cursor-pointer" onClick={() => setSelectedPropertyId(p.id)}>
                      <div className="font-bold text-slate-800 group-hover:text-emerald-600 transition-colors">{p.name}</div>
                      <div className="text-[9px] text-slate-400 font-bold uppercase truncate max-w-[150px]">{p.address}</div>
                    </td>

                    {/* Month statuses */}
                    {lastSixMonths.map((month, idx) => {
                      const bill = propertyBills.find(b => b.month === month);
                      return (
                        <td key={month} className={`px-4 py-6 text-center ${idx === 0 ? 'bg-emerald-50/10' : ''}`}>
                          {bill ? (
                            <div className="flex justify-center">
                              <div className={`w-3 h-3 rounded-full shadow-sm ${bill.status === BillStatus.PAID ? 'bg-emerald-500' : 'bg-rose-500'}`} title={`${month}: ${bill.status}`}></div>
                            </div>
                          ) : (
                            <div className="w-3 h-3 rounded-full bg-slate-200 mx-auto opacity-30"></div>
                          )}
                        </td>
                      );
                    })}

                    <td className="px-8 py-6 text-right">
                      <div className="flex items-center justify-end gap-2">
                        {currentBill && currentBill.status === BillStatus.UNPAID ? (
                          <button 
                            onClick={() => onUpdateStatus(currentBill.id, BillStatus.PAID)}
                            className="bg-emerald-600 hover:bg-emerald-700 text-white px-4 py-2 rounded-lg text-[9px] font-black uppercase tracking-wider shadow-md transition-all active:scale-95"
                          >
                            Mark Paid
                          </button>
                        ) : currentBill ? (
                          <button 
                            onClick={() => onUpdateStatus(currentBill.id, BillStatus.UNPAID)}
                            className="text-[9px] font-black text-rose-500 uppercase hover:underline"
                          >
                            Unmark
                          </button>
                        ) : (
                          <span className="text-[9px] font-black text-slate-300 uppercase">No Bill</span>
                        )}
                        <button 
                          onClick={() => setSelectedPropertyId(p.id)}
                          className="w-8 h-8 text-slate-300 hover:text-indigo-600 transition-colors"
                          title="View History"
                        >
                          <i className="fas fa-ellipsis-v"></i>
                        </button>
                      </div>
                    </td>
                  </tr>
                )
              })}
            </tbody>
          </table>
        </div>
      </div>

      {selectedPropertyId && (
        <PropertyDetails 
          property={properties.find(p => p.id === selectedPropertyId)!}
          bills={bills.filter(b => b.propertyId === selectedPropertyId)}
          onClose={() => setSelectedPropertyId(null)}
          onUpdateStatus={onUpdateStatus}
          isAdmin={true}
        />
      )}
    </div>
  );
};

