import React, { useState } from 'react';
import Layout from './components/Layout';
import SuperAdminView from './components/SuperAdminView';
import AdminView from './components/AdminView';
import { User, Property, Bill, BillStatus } from './types';
import { authService } from './services/authService';
import { MOCK_PROPERTIES as props, MOCK_BILLS as billsData, MOCK_USERS } from './services/mockData';

const App: React.FC = () => {
  const [user, setUser] = useState<User | null>(null);
  const [properties, setProperties] = useState<Property[]>(props);
  const [bills, setBills] = useState<Bill[]>(billsData);
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [error, setError] = useState('');
  const [isLoggingIn, setIsLoggingIn] = useState(false);

  const handleLogin = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsLoggingIn(true);
    setError('');

    try {
      const authenticatedUser = await authService.login(email, password);
      setUser(authenticatedUser);
    } catch (err: any) {
      setError(err.message || 'An error occurred during login');
    } finally {
      setIsLoggingIn(false);
    }
  };

  const handleLogout = () => {
    setUser(null);
    setEmail('');
    setPassword('');
    setError('');
  };

  const handleAddProperty = (name: string, address: string) => {
    const propertyId = `p${properties.length + 1}`;
    const newProperty: Property = {
      id: propertyId,
      name,
      address,
      totalPendingAmount: 0
    };

    // Generate bills for the last 6 months for the new property
    const newBills: Bill[] = [];
    const date = new Date();
    const monthNames = ["January", "February", "March", "April", "May", "June", "July", "August", "September", "October", "November", "December"];

    for (let i = 0; i < 6; i++) {
      const d = new Date(date.getFullYear(), date.getMonth() - i, 1);
      const monthStr = `${monthNames[d.getMonth()]} ${d.getFullYear()}`;

      newBills.push({
        id: `b-${propertyId}-${i}`,
        propertyId: propertyId,
        month: monthStr,
        amount: Math.floor(Math.random() * 100) + 50,
        consumption: Math.floor(Math.random() * 300) + 150,
        status: i === 0 ? BillStatus.UNPAID : BillStatus.PAID,
        dueDate: '2024-05-10'
      });
    }

    setProperties([...properties, newProperty]);
    setBills([...bills, ...newBills]);
  };

  const updateBillStatus = (billId: string, newStatus: BillStatus) => {
    setBills(prev => prev.map(b => b.id === billId ? { ...b, status: newStatus } : b));
  };

  const fillDemoCredentials = (role: 'SUPER_ADMIN' | 'ADMIN') => {
    const demoUser = MOCK_USERS.find(u => u.role === role);
    if (demoUser) {
      setEmail(demoUser.email);
      setPassword(demoUser.password || 'password123');
    }
  };

  if (!user) {
    return (
      <div className="min-h-screen flex items-center justify-center bg-slate-50 px-4 relative overflow-hidden font-sans">
        <div className="absolute inset-0 z-0 pointer-events-none opacity-30">
          <div className="absolute top-0 right-0 w-[500px] h-[500px] bg-indigo-200 rounded-full blur-[120px] -mr-64 -mt-64"></div>
          <div className="absolute bottom-0 left-0 w-[500px] h-[500px] bg-emerald-100 rounded-full blur-[120px] -ml-64 -mb-64"></div>
        </div>

        <div className="max-w-md w-full bg-white/80 backdrop-blur-xl rounded-[40px] shadow-2xl p-10 border border-white/50 relative z-10">
          <div className="flex flex-col items-center mb-8 text-center">
            <div className="w-16 h-16 bg-gradient-to-br from-indigo-600 to-indigo-700 rounded-2xl mb-4 shadow-xl shadow-indigo-100 flex items-center justify-center">
              <i className="fas fa-bolt text-white text-3xl"></i>
            </div>
            <h1 className="text-2xl font-black text-slate-800 tracking-tight">ElectraFlow</h1>
            <p className="text-slate-400 mt-1 font-semibold uppercase tracking-widest text-[9px]">Management Enterprise</p>
          </div>

          <form onSubmit={handleLogin} className="space-y-5">
            <div className="space-y-1.5">
              <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest px-1">Identity (Email)</label>
              <input 
                type="email" 
                value={email}
                onChange={(e) => setEmail(e.target.value)}
                placeholder="identity@electra.com"
                className="w-full px-5 py-3.5 bg-slate-50 border border-slate-100 rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none transition-all font-medium text-slate-700"
                required 
              />
            </div>
            <div className="space-y-1.5">
              <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest px-1">Access Key (Password)</label>
              <input 
                type="password" 
                value={password}
                onChange={(e) => setPassword(e.target.value)}
                placeholder="••••••••"
                className="w-full px-5 py-3.5 bg-slate-50 border border-slate-100 rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none transition-all font-medium text-slate-700"
                required 
              />
            </div>

            {error && (
              <div className="p-3 bg-rose-50 text-rose-600 text-[11px] font-bold rounded-xl border border-rose-100 animate-shake text-center">
                {error}
              </div>
            )}

            <button 
              type="submit" 
              disabled={isLoggingIn}
              className="w-full bg-slate-800 hover:bg-slate-900 text-white font-black py-4 rounded-xl shadow-lg transition-all active:scale-[0.98] disabled:opacity-50"
            >
              {isLoggingIn ? 'Verifying Access...' : 'Authenticate'}
            </button>
          </form>

          <div className="mt-8 pt-6 border-t border-slate-100">
            <p className="text-[10px] font-black text-slate-400 uppercase tracking-[0.2em] text-center mb-4">Demo Credentials</p>
            <div className="grid grid-cols-1 gap-2">
              <button 
                onClick={() => fillDemoCredentials('SUPER_ADMIN')}
                className="flex items-center justify-between p-3 bg-indigo-50 hover:bg-indigo-100 border border-indigo-100 rounded-xl transition-colors group"
              >
                <div className="text-left">
                  <p className="text-[9px] font-black text-indigo-400 uppercase">Super Admin</p>
                  <p className="text-xs font-bold text-indigo-700">super@electra.com</p>
                </div>
                <i className="fas fa-chevron-right text-[10px] text-indigo-300 group-hover:translate-x-1 transition-transform"></i>
              </button>

              <button 
                onClick={() => fillDemoCredentials('ADMIN')}
                className="flex items-center justify-between p-3 bg-emerald-50 hover:bg-emerald-100 border border-emerald-100 rounded-xl transition-colors group"
              >
                <div className="text-left">
                  <p className="text-[9px] font-black text-emerald-400 uppercase">Staff Admin</p>
                  <p className="text-xs font-bold text-emerald-700">admin@electra.com</p>
                </div>
                <i className="fas fa-chevron-right text-[10px] text-emerald-300 group-hover:translate-x-1 transition-transform"></i>
              </button>
            </div>
            <p className="mt-3 text-[10px] text-slate-400 text-center font-medium">Password for all: <span className="font-bold text-slate-500">password123</span></p>
          </div>
        </div>

        <style dangerouslySetInnerHTML={{ __html: `
          @keyframes shake { 0%, 100% { transform: translateX(0); } 25% { transform: translateX(-3px); } 75% { transform: translateX(3px); } }
          .animate-shake { animation: shake 0.2s ease-in-out 0s 2; }
          .animate-fadeIn { animation: fadeIn 0.4s ease-out; }
          .animate-scaleUp { animation: scaleUp 0.3s cubic-bezier(0.34, 1.56, 0.64, 1); }
          @keyframes fadeIn { from { opacity: 0; transform: translateY(10px); } to { opacity: 1; transform: translateY(0); } }
          @keyframes scaleUp { from { opacity: 0; transform: scale(0.9); } to { opacity: 1; transform: scale(1); } }
        `}} />
      </div>
    );
  }

  return (
    <Layout user={user} onLogout={handleLogout}>
      {user.role === 'SUPER_ADMIN' ? (
        <SuperAdminView 
          properties={properties} 
          bills={bills}
          onAddProperty={handleAddProperty}
        />
      ) : (
        <AdminView 
          properties={properties} 
          bills={bills} 
          onUpdateStatus={updateBillStatus} 
        />
      )}
    </Layout>
  );
};

export default App;

import React, { useState, useMemo } from 'react';
