                              <button 
                                onClick={() => onUpdateStatus(monthBill.id, BillStatus.PAID)}
                                className="bg-emerald-600 hover:bg-emerald-700 text-white px-5 py-2.5 rounded-xl text-[10px] font-black uppercase tracking-wider shadow-lg shadow-emerald-100 transition-all active:scale-95 flex items-center gap-2"
