                        ) : null}

                        <button 
                          onClick={() => setSelectedPropertyId(p.id)}
                          className="w-10 h-10 bg-slate-50 text-slate-400 rounded-xl flex items-center justify-center hover:bg-white hover:text-indigo-600 hover:shadow-md transition-all border border-transparent hover:border-slate-100"
                          title="Full Profile & History"
                        >
                          <i className="fas fa-chevron-right text-xs"></i>
                        </button>
                      </div>
                    </td>
                  </tr>
                )
              })}
            </tbody>
          </table>
        </div>
      </div>

      {selectedPropertyId && (
        <PropertyDetails 
          property={properties.find(p => p.id === selectedPropertyId)!}
          bills={bills.filter(b => b.propertyId === selectedPropertyId)}
          onClose={() => setSelectedPropertyId(null)}
          onUpdateStatus={onUpdateStatus}
          isAdmin={true}
        />
      )}
    </div>
  );
};

