                <label className="text-[10px] font-black text-slate-400 uppercase tracking-[0.2em] px-1">Building Name</label>
                <input 
                  autoFocus
                  required
                  className="w-full p-4 bg-slate-50 border border-slate-100 rounded-xl focus:ring-4 focus:ring-blue-500/10 outline-none font-bold text-slate-800"
                  placeholder="e.g. Ocean View"
