              className="w-full bg-slate-900 hover:bg-black text-white font-black py-4 rounded-2xl shadow-xl transition-all active:scale-[0.98] disabled:opacity-50 text-xs uppercase tracking-[0.2em]"
            >
              {isLoggingIn ? 'Verifying...' : 'Login'}
            </button>
          </form>

          <div className="mt-8 pt-6 border-t border-slate-100 flex flex-col gap-2">
            <button onClick={() => fillDemoCredentials('SUPER_ADMIN')} className="text-[9px] font-black text-blue-600 uppercase tracking-widest hover:underline text-center">Login as Super Admin</button>
            <button onClick={() => fillDemoCredentials('ADMIN')} className="text-[9px] font-black text-slate-400 uppercase tracking-widest hover:underline text-center">Login as Field Admin</button>
          </div>
        </div>

        <style dangerouslySetInnerHTML={{ __html: `
          .animate-fadeIn { animation: fadeIn 0.4s ease-out; }
          .animate-scaleUp { animation: scaleUp 0.3s cubic-bezier(0.34, 1.56, 0.64, 1); }
          @keyframes fadeIn { from { opacity: 0; transform: translateY(10px); } to { opacity: 1; transform: translateY(0); } }
          @keyframes scaleUp { from { opacity: 0; transform: scale(0.95); } to { opacity: 1; transform: scale(1); } }
