import React, { useState, useMemo } from 'react';
import { Property, Bill, BillStatus } from '../types';
import PropertyDetails from './PropertyDetails';

interface AdminViewProps {
  properties: Property[];
  bills: Bill[];
  onUpdateStatus: (billId: string, newStatus: BillStatus) => void;
}

const AdminView: React.FC<AdminViewProps> = ({ properties, bills, onUpdateStatus }) => {
  const [selectedPropertyId, setSelectedPropertyId] = useState<string | null>(null);
  const [searchQuery, setSearchQuery] = useState('');

  // Generate the last 6 months for the selection
  const monthOptions = useMemo(() => {
    const months = [];
    const date = new Date();
    const monthNames = ["January", "February", "March", "April", "May", "June", "July", "August", "September", "October", "November", "December"];

    for (let i = 0; i < 6; i++) {
      const d = new Date(date.getFullYear(), date.getMonth() - i, 1);
      months.push(`${monthNames[d.getMonth()]} ${d.getFullYear()}`);
    }
    return months;
  }, []);

  const [selectedMonth, setSelectedMonth] = useState(monthOptions[0]);

  const filteredProperties = properties.filter(p => 
    p.name.toLowerCase().includes(searchQuery.toLowerCase())
  );

  return (
    <div className="max-w-4xl mx-auto space-y-6 animate-fadeIn pb-20">
      <div className="flex flex-col md:flex-row justify-between items-center gap-4 bg-white p-6 rounded-[2rem] shadow-sm border border-slate-100">
        <div className="w-full md:w-auto">
          <h1 className="text-2xl font-black text-slate-800 tracking-tight">Billing Center</h1>
          <p className="text-slate-400 text-xs font-bold uppercase tracking-widest">{selectedMonth}</p>
        </div>

        <div className="flex flex-col sm:flex-row gap-3 w-full md:w-auto">
          <div className="relative">
            <select 
              value={selectedMonth}
              onChange={(e) => setSelectedMonth(e.target.value)}
              className="w-full px-4 py-2.5 bg-slate-50 border border-slate-100 rounded-xl font-bold text-slate-700 outline-none focus:ring-2 focus:ring-blue-500 transition-all text-sm appearance-none pr-10"
            >
              {monthOptions.map(m => <option key={m} value={m}>{m}</option>)}
            </select>
            <i className="fas fa-chevron-down absolute right-4 top-1/2 -translate-y-1/2 text-slate-400 pointer-events-none text-xs"></i>
          </div>

          <div className="relative">
            <i className="fas fa-search absolute left-3.5 top-1/2 -translate-y-1/2 text-slate-300 text-xs"></i>
            <input 
              type="text"
              placeholder="Search property..."
              value={searchQuery}
              onChange={e => setSearchQuery(e.target.value)}
              className="pl-9 pr-4 py-2.5 bg-slate-50 border border-slate-100 rounded-xl outline-none focus:ring-2 focus:ring-blue-500 transition-all text-sm font-medium w-full sm:w-48"
            />
          </div>
        </div>
      </div>

      <div className="bg-white rounded-[2rem] border border-slate-100 shadow-xl overflow-hidden">
        <table className="w-full text-left">
          <thead>
            <tr className="text-[10px] font-black text-slate-400 uppercase tracking-[0.2em] bg-slate-50/50">
              <th className="px-8 py-5">Property Name</th>
              <th className="px-8 py-5 text-center">Payment Status</th>
              <th className="px-8 py-5 text-right">Details</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-slate-50">
            {filteredProperties.length === 0 ? (
              <tr>
                <td colSpan={3} className="px-8 py-16 text-center text-slate-400 font-medium italic">No results found.</td>
              </tr>
            ) : filteredProperties.map(p => {
              const monthBill = bills.find(b => b.propertyId === p.id && b.month === selectedMonth);

              return (
                <tr key={p.id} className="group hover:bg-slate-50/50 transition-all">
                  <td className="px-8 py-6 font-bold text-slate-800">{p.name}</td>
                  <td className="px-8 py-6">
                    <div className="flex justify-center">
                      {monthBill ? (
                        <button 
                          onClick={() => onUpdateStatus(monthBill.id, monthBill.status === BillStatus.PAID ? BillStatus.UNPAID : BillStatus.PAID)}
                          className={`min-w-[120px] px-4 py-2 rounded-full text-[10px] font-black uppercase tracking-widest transition-all active:scale-95 shadow-sm border ${
                            monthBill.status === BillStatus.PAID 
                            ? 'bg-emerald-500 text-white border-emerald-400 hover:bg-emerald-600 shadow-emerald-100' 
                            : 'bg-rose-500 text-white border-rose-400 hover:bg-rose-600 shadow-rose-100'
                          }`}
                        >
                          <i className={`fas ${monthBill.status === BillStatus.PAID ? 'fa-check-circle' : 'fa-clock'} mr-2`}></i>
                          {monthBill.status}
                        </button>
                      ) : (
                        <span className="text-slate-300 text-[10px] font-black uppercase tracking-widest italic">Not Found</span>
                      )}
                    </div>
                  </td>
                  <td className="px-8 py-6 text-right">
                    <button 
                      onClick={() => setSelectedPropertyId(p.id)}
                      className="text-slate-300 hover:text-blue-600 transition-colors"
                    >
                      <i className="fas fa-history text-sm"></i>
                    </button>
                  </td>
                </tr>
              )
            })}
          </tbody>
        </table>
      </div>

      {selectedPropertyId && (
        <PropertyDetails 
          property={properties.find(p => p.id === selectedPropertyId)!}
          bills={bills.filter(b => b.propertyId === selectedPropertyId)}
          onClose={() => setSelectedPropertyId(null)}
          onUpdateStatus={onUpdateStatus}
          isAdmin={true}
        />
      )}
    </div>
  );
};

