import React, { useState } from 'react';
import Layout from './components/Layout';
import SuperAdminView from './components/SuperAdminView';
import AdminView from './components/AdminView';
import OwnerView from './components/OwnerView';
import { User, Property, Bill, BillStatus } from './types';
import { authService } from './services/authService';
import { MOCK_PROPERTIES as props, MOCK_BILLS as billsData, MOCK_USERS } from './services/mockData';

const App: React.FC = () => {
  const [user, setUser] = useState<User | null>(null);
  const [properties, setProperties] = useState<Property[]>(props);
  const [bills, setBills] = useState<Bill[]>(billsData);
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [error, setError] = useState('');
  const [isLoggingIn, setIsLoggingIn] = useState(false);

  const handleLogin = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsLoggingIn(true);
    setError('');

    try {
      const authenticatedUser = await authService.login(email, password);
      setUser(authenticatedUser);
    } catch (err: any) {
      setError(err.message || 'An error occurred during login');
    } finally {
      setIsLoggingIn(false);
    }
  };

  const handleLogout = () => {
    setUser(null);
    setEmail('');
    setPassword('');
    setError('');
  };

  const handleAddProperty = (name: string, address: string) => {
    const propertyId = `p${properties.length + 1}`;
    const newProperty: Property = {
      id: propertyId,
      name,
      address,
      totalPendingAmount: 0
    };

    const newBills: Bill[] = [];
    const date = new Date();
    const monthNames = ["January", "February", "March", "April", "May", "June", "July", "August", "September", "October", "November", "December"];

    for (let i = 0; i < 6; i++) {
      const d = new Date(date.getFullYear(), date.getMonth() - i, 1);
      const monthStr = `${monthNames[d.getMonth()]} ${d.getFullYear()}`;

      newBills.push({
        id: `b-${propertyId}-${i}`,
        propertyId: propertyId,
        month: monthStr,
        amount: 0,
        consumption: 0,
        status: i === 0 ? BillStatus.UNPAID : BillStatus.PAID,
        dueDate: `${d.getFullYear()}-${String(d.getMonth() + 1).padStart(2, '0')}-10`
      });
    }

    setProperties(prev => [...prev, newProperty]);
    setBills(prev => [...prev, ...newBills]);
  };

  const updateBillStatus = (billId: string, newStatus: BillStatus) => {
    setBills(prev => prev.map(b => b.id === billId ? { ...b, status: newStatus } : b));
  };

  const fillDemoCredentials = (role: 'SUPER_ADMIN' | 'ADMIN' | 'OWNER') => {
    const demoUser = MOCK_USERS.find(u => u.role === role);
    if (demoUser) {
      setEmail(demoUser.email);
      setPassword(demoUser.password || 'password123');
    }
  };

  if (!user) {
    return (
      <div className="min-h-screen flex items-center justify-center bg-slate-50 px-4 relative overflow-hidden">
        <div className="max-w-md w-full bg-white rounded-[3rem] shadow-2xl p-10 border border-slate-100 relative z-10">
          <div className="flex flex-col items-center mb-10 text-center">
            <div className="w-16 h-16 bg-blue-600 rounded-2xl mb-4 shadow-xl shadow-blue-100 flex items-center justify-center text-white text-3xl">
              <i className="fas fa-bolt"></i>
            </div>
            <h1 className="text-2xl font-black text-slate-800 tracking-tight">ElectraFlow</h1>
            <p className="text-slate-400 mt-1 font-black uppercase tracking-widest text-[8px]">Minimal Bill Management</p>
          </div>

          <form onSubmit={handleLogin} className="space-y-4">
            <input 
              type="email" 
              value={email}
              onChange={(e) => setEmail(e.target.value)}
              placeholder="Email Address"
              className="w-full px-5 py-4 bg-slate-50 border border-slate-100 rounded-2xl outline-none transition-all font-bold text-slate-700"
              required 
            />
            <input 
              type="password" 
              value={password}
              onChange={(e) => setPassword(e.target.value)}
              placeholder="Password"
              className="w-full px-5 py-4 bg-slate-50 border border-slate-100 rounded-2xl outline-none transition-all font-bold text-slate-700"
              required 
            />

            {error && <div className="p-3 bg-rose-50 text-rose-600 text-[10px] font-black rounded-xl border border-rose-100 text-center uppercase">{error}</div>}

            <button 
              type="submit" 
              disabled={isLoggingIn}
              className="w-full bg-slate-900 hover:bg-black text-white font-black py-4 rounded-2xl shadow-xl transition-all active:scale-[0.98] disabled:opacity-50 text-xs uppercase tracking-widest"
            >
              {isLoggingIn ? 'Logging in...' : 'Sign In'}
            </button>
          </form>

          <div className="mt-8 pt-6 border-t border-slate-50 flex flex-wrap justify-center gap-4">
            <button onClick={() => fillDemoCredentials('SUPER_ADMIN')} className="text-[9px] font-black text-blue-600 uppercase tracking-widest hover:underline">Super Admin</button>
            <button onClick={() => fillDemoCredentials('ADMIN')} className="text-[9px] font-black text-slate-400 uppercase tracking-widest hover:underline">Field Admin</button>
            <button onClick={() => fillDemoCredentials('OWNER')} className="text-[9px] font-black text-emerald-600 uppercase tracking-widest hover:underline">Property Owner</button>
          </div>
        </div>
        <style dangerouslySetInnerHTML={{ __html: `
          .animate-fadeIn { animation: fadeIn 0.4s ease-out; }
          .animate-scaleUp { animation: scaleUp 0.3s cubic-bezier(0.34, 1.56, 0.64, 1); }
          @keyframes fadeIn { from { opacity: 0; transform: translateY(10px); } to { opacity: 1; transform: translateY(0); } }
          @keyframes scaleUp { from { opacity: 0; transform: scale(0.95); } to { opacity: 1; transform: scale(1); } }
        `}} />
      </div>
    );
  }

  const renderView = () => {
    switch(user.role) {
      case 'SUPER_ADMIN':
        return <SuperAdminView properties={properties} bills={bills} onAddProperty={handleAddProperty} />;
      case 'ADMIN':
        return <AdminView properties={properties} bills={bills} onUpdateStatus={updateBillStatus} />;
      case 'OWNER':
        const ownerProperty = properties.find(p => p.id === user.propertyId);
        const ownerBills = bills.filter(b => b.propertyId === user.propertyId);
        return ownerProperty ? <OwnerView property={ownerProperty} bills={ownerBills} /> : <div>Property not found</div>;
      default:
        return <div>Access Denied</div>;
    }
  };

  return (
    <Layout user={user} onLogout={handleLogout}>
      {renderView()}
    </Layout>
  );
};

export default App;

import React, { useState, useMemo } from 'react';
