}

const AdminView: React.FC<AdminViewProps> = ({ properties, bills, onUpdateStatus }) => {
  const [selectedPropertyId, setSelectedPropertyId] = useState<string | null>(null);
  const [searchQuery, setSearchQuery] = useState('');

  // Generate the last 6 months for the selection
  const monthOptions = useMemo(() => {
    const months = [];
    const date = new Date();
    const monthNames = ["January", "February", "March", "April", "May", "June", "July", "August", "September", "October", "November", "December"];

    for (let i = 0; i < 6; i++) {
      const d = new Date(date.getFullYear(), date.getMonth() - i, 1);
      months.push(`${monthNames[d.getMonth()]} ${d.getFullYear()}`);
    }
    return months;
  }, []);

  const [selectedMonth, setSelectedMonth] = useState(monthOptions[0]);

  // Logic: Only the 3 most recent months are editable
  const isMonthEditable = useMemo(() => {
    return monthOptions.slice(0, 3).includes(selectedMonth);
  }, [selectedMonth, monthOptions]);

  const filteredProperties = properties.filter(p => 
    p.name.toLowerCase().includes(searchQuery.toLowerCase())
  );

  return (
    <div className="max-w-4xl mx-auto space-y-6 animate-fadeIn pb-20">
