      <div className="bg-white rounded-[2rem] border border-slate-100 shadow-xl overflow-hidden">
        <table className="w-full text-left">
          <thead>
            <tr className="text-[10px] font-black text-slate-400 uppercase tracking-[0.2em] bg-slate-50/50">
              <th className="px-8 py-5">Property Name</th>
              <th className="px-8 py-5 text-center">Status</th>
              <th className="px-8 py-5 text-right">View History</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-slate-50">
            {filteredProperties.map(p => {
              const monthBill = bills.find(b => b.propertyId === p.id && b.month === selectedMonth);

              return (
                <tr key={p.id} className="group hover:bg-slate-50/50 transition-all">
                  <td className="px-8 py-6 font-bold text-slate-800">{p.name}</td>
                  <td className="px-8 py-6">
                    <div className="flex justify-center">
                      {monthBill ? (
                        <button 
                          disabled={!isMonthEditable}
                          onClick={() => onUpdateStatus(monthBill.id, monthBill.status === BillStatus.PAID ? BillStatus.UNPAID : BillStatus.PAID)}
                          className={`min-w-[120px] px-4 py-2 rounded-full text-[10px] font-black uppercase tracking-widest transition-all shadow-sm border ${
                            !isMonthEditable 
                            ? 'bg-slate-50 text-slate-300 border-slate-100 cursor-not-allowed opacity-75' 
                            : monthBill.status === BillStatus.PAID 
                            ? 'bg-emerald-500 text-white border-emerald-400 hover:bg-emerald-600 active:scale-95' 
                            : 'bg-rose-500 text-white border-rose-400 hover:bg-rose-600 active:scale-95'
                          }`}
                          title={!isMonthEditable ? "Editing locked for historical bills" : ""}
                        >
                          <i className={`fas ${monthBill.status === BillStatus.PAID ? 'fa-check-circle' : 'fa-clock'} mr-2`}></i>
                          {monthBill.status}
                        </button>
                      ) : (
                        <span className="text-slate-300 text-[10px] font-black uppercase tracking-widest italic">Waitlisting</span>
                      )}
