          </div>

          <form onSubmit={handleLogin} className="space-y-4">
            <input 
              type="email" 
              value={email}
              onChange={(e) => setEmail(e.target.value)}
              placeholder="Email Address"
              className="w-full px-5 py-4 bg-slate-50 border border-slate-100 rounded-2xl outline-none transition-all font-bold text-slate-700"
              required 
            />
            <input 
              type="password" 
              value={password}
              onChange={(e) => setPassword(e.target.value)}
              placeholder="Password"
              className="w-full px-5 py-4 bg-slate-50 border border-slate-100 rounded-2xl outline-none transition-all font-bold text-slate-700"
              required 
            />

            {error && <div className="p-3 bg-rose-50 text-rose-600 text-[10px] font-black rounded-xl border border-rose-100 text-center uppercase">{error}</div>}

            <button 
              type="submit" 
              disabled={isLoggingIn}
              className="w-full bg-slate-900 hover:bg-black text-white font-black py-4 rounded-2xl shadow-xl transition-all active:scale-[0.98] disabled:opacity-50 text-xs uppercase tracking-widest"
            >
              {isLoggingIn ? 'Logging in...' : 'Sign In'}
            </button>
          </form>

          <div className="mt-8 pt-6 border-t border-slate-50 flex flex-wrap justify-center gap-4">
            <button onClick={() => fillDemoCredentials('SUPER_ADMIN')} className="text-[9px] font-black text-blue-600 uppercase tracking-widest hover:underline">Super Admin</button>
            <button onClick={() => fillDemoCredentials('ADMIN')} className="text-[9px] font-black text-slate-400 uppercase tracking-widest hover:underline">Field Admin</button>
          </div>
        </div>
        <style dangerouslySetInnerHTML={{ __html: `
          .animate-fadeIn { animation: fadeIn 0.4s ease-out; }
          .animate-scaleUp { animation: scaleUp 0.3s cubic-bezier(0.34, 1.56, 0.64, 1); }
          @keyframes fadeIn { from { opacity: 0; transform: translateY(10px); } to { opacity: 1; transform: translateY(0); } }
          @keyframes scaleUp { from { opacity: 0; transform: scale(0.95); } to { opacity: 1; transform: scale(1); } }
        `}} />
      </div>
    );
  }

  const renderView = () => {
    switch(user.role) {
      case 'SUPER_ADMIN':
        return <SuperAdminView properties={properties} bills={bills} onAddProperty={handleAddProperty} />;
      case 'ADMIN':
        return <AdminView properties={properties} bills={bills} onUpdateStatus={updateBillStatus} />;
      default:
        return <div>Access Denied</div>;
    }
  };

  return (
    <Layout user={user} onLogout={handleLogout}>
      {renderView()}
    </Layout>
  );
};

