import { Property, Bill, BillStatus, User, AuditLog, UserRole } from '../types';
import { MOCK_PROPERTIES, MOCK_BILLS } from './mockData';

// Simulated Server-Side Data Store
let properties: Property[] = [...MOCK_PROPERTIES];
let bills: Bill[] = [...MOCK_BILLS];
let auditLogs: AuditLog[] = [];

// Helper to calculate editable months (Current + 2 previous)
const getEditableMonths = (): string[] => {
  const months = [];
  const date = new Date();
  const monthNames = ["January", "February", "March", "April", "May", "June", "July", "August", "September", "October", "November", "December"];

  for (let i = 0; i < 3; i++) {
    const d = new Date(date.getFullYear(), date.getMonth() - i, 1);
    months.push(`${monthNames[d.getMonth()]} ${d.getFullYear()}`);
  }
  return months;
};

/**
 * SIMULATED BACKEND API
 * In a real app, these would be fetch() calls to a Node.js/Express server.
 */
export const api = {
  // Fetch properties (accessible by both roles)
  getProperties: async (): Promise<Property[]> => {
    return [...properties];
  },

  // Fetch bills (accessible by both roles)
  getBills: async (): Promise<Bill[]> => {
    return [...bills];
  },

  // Super Admin Only: Add Property
  addProperty: async (user: User, name: string, address: string): Promise<{property: Property, bills: Bill[]}> => {
    if (user.role !== 'SUPER_ADMIN') {
      throw new Error('403 Forbidden: Only Super Admins can provision assets.');
    }

    const propertyId = `p${properties.length + 1}`;
    const newProperty: Property = {
      id: propertyId,
      name,
      address,
      totalPendingAmount: 0
    };

    const newBills: Bill[] = [];
    const date = new Date();
    const monthNames = ["January", "February", "March", "April", "May", "June", "July", "August", "September", "October", "November", "December"];

    // Auto-generate 6 months history
    for (let i = 0; i < 6; i++) {
      const d = new Date(date.getFullYear(), date.getMonth() - i, 1);
      const monthStr = `${monthNames[d.getMonth()]} ${d.getFullYear()}`;
      newBills.push({
        id: `b-${propertyId}-${i}`,
        propertyId,
        month: monthStr,
        amount: Math.floor(Math.random() * 150) + 50,
        consumption: Math.floor(Math.random() * 300) + 100,
        status: i === 0 ? BillStatus.UNPAID : BillStatus.PAID,
        dueDate: `${d.getFullYear()}-${String(d.getMonth() + 1).padStart(2, '0')}-10`
      });
    }

    properties = [...properties, newProperty];
    bills = [...bills, ...newBills];
    return { property: newProperty, bills: newBills };
  },

  // Admin Only: Update Bill Status (with strict 3-month locking)
  updateBillStatus: async (user: User, billId: string, newStatus: BillStatus): Promise<Bill> => {
    if (user.role !== 'ADMIN') {
      throw new Error('403 Forbidden: Only Field Admins can update bill statuses.');
    }

    const billIndex = bills.findIndex(b => b.id === billId);
    if (billIndex === -1) throw new Error('404 Not Found: Bill record missing.');

    const bill = bills[billIndex];
    const editableMonths = getEditableMonths();

    // Check time-restricted locking logic
    if (!editableMonths.includes(bill.month)) {
      throw new Error('400 Bad Request: Editing locked for historical bills older than 3 months.');
    }

    const oldStatus = bill.status;
    const updatedBill = { ...bill, status: newStatus };

    // Create Audit Log
    const prop = properties.find(p => p.id === bill.propertyId);
    const log: AuditLog = {
      id: `log-${Date.now()}`,
      propertyId: bill.propertyId,
      propertyName: prop?.name || 'Unknown',
      billMonth: bill.month,
      oldStatus: oldStatus,
      newStatus: newStatus,
      updatedBy: user.name,
      updatedById: user.id,
      timestamp: new Date().toISOString()
    };

    bills[billIndex] = updatedBill;
    auditLogs = [log, ...auditLogs];

    return updatedBill;
  },

  // Super Admin Only: View Audit Logs
  getAuditLogs: async (user: User): Promise<AuditLog[]> => {
    if (user.role !== 'SUPER_ADMIN') {
      throw new Error('403 Forbidden: Access restricted to Super Admin.');
    }
    return [...auditLogs];
  }
};

