            </button>
          </div>
        </div>
      )}

      {showAddProp && (
        <div className="fixed inset-0 bg-slate-900/40 backdrop-blur-sm z-[200] flex items-center justify-center p-4">
          <div className="bg-white rounded-[3rem] shadow-2xl w-full max-w-sm p-10 animate-scaleUp">
            <h2 className="text-2xl font-black text-slate-800 mb-6 text-center">New Property</h2>
            <form onSubmit={(e) => {
              e.preventDefault();
              const d = new FormData(e.currentTarget);
              onAddProperty(d.get('name') as string, d.get('address') as string);
              setShowAddProp(false);
            }} className="space-y-4">
              <input name="name" required placeholder="Asset Name" className="w-full p-4 bg-slate-50 border border-slate-100 rounded-2xl font-bold outline-none" />
              <input name="address" required placeholder="Location" className="w-full p-4 bg-slate-50 border border-slate-100 rounded-2xl font-bold outline-none" />
              <button type="submit" className="w-full py-4 bg-blue-600 text-white rounded-2xl font-black uppercase text-[10px] tracking-widest shadow-xl">Create Asset</button>
              <button type="button" onClick={() => setShowAddProp(false)} className="w-full py-2 text-slate-400 font-bold uppercase text-[9px]">Discard</button>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

