interface AdminViewProps {
  properties: Property[];
  bills: Bill[];
  onUpdateStatus: (billId: string, newStatus: BillStatus) => void;
  user: any;
}

const AdminView: React.FC<AdminViewProps> = ({ properties, bills, onUpdateStatus, user }) => {
  const [billTypes, setBillTypes] = useState<BillType[]>([]);
  const [showEntryPanel, setShowEntryPanel] = useState(false);
