  const [entryBillTypeId, setEntryBillTypeId] = useState<string>('');
  const [entryPropertyId, setEntryPropertyId] = useState<string>('');

  useEffect(() => {
    api.getBillTypes().then(setBillTypes);
  }, []);

  const monthOptions = useMemo(() => {
    const months = [];
    const date = new Date();
    const monthNames = ["January", "February", "March", "April", "May", "June", "July", "August", "September", "October", "November", "December"];
    for (let i = 0; i < 6; i++) {
      const d = new Date(date.getFullYear(), date.getMonth() - i, 1);
      months.push(`${monthNames[d.getMonth()]} ${d.getFullYear()}`);
    }
    return months;
  }, []);

  const [selectedMonth, setSelectedMonth] = useState(monthOptions[0]);
  const isMonthEditable = monthOptions.slice(0, 3).includes(selectedMonth);

  const activeProperty = properties.find(p => p.id === activePropertyId);
  const entryBillType = billTypes.find(bt => bt.id === entryBillTypeId);

  useEffect(() => {
    if (showEntryPanel) {
      setEntryPropertyId(activePropertyId || properties[0]?.id || '');
    }
  }, [showEntryPanel, activePropertyId, properties]);

  useEffect(() => {
    if (entryPropertyId) {
      const prop = properties.find(p => p.id === entryPropertyId);
      if (prop && prop.activeBillTypeIds.length > 0) {
        setEntryBillTypeId(prop.activeBillTypeIds[0]);
      } else {
        setEntryBillTypeId('');
      }
    }
  }, [entryPropertyId, properties]);

  return (
    <div className="max-w-6xl mx-auto space-y-6 animate-fadeIn pb-20">
      <div className="flex flex-col md:flex-row justify-between items-center gap-6 bg-white p-8 rounded-[2.5rem] shadow-sm border border-slate-100">
