import { Property, Bill, BillStatus, User, AuditLog, BillType } from '../types';
import { MOCK_PROPERTIES, MOCK_BILLS, MOCK_BILL_TYPES } from './mockData';

let properties: Property[] = [...MOCK_PROPERTIES];
let bills: Bill[] = [...MOCK_BILLS];
let billTypes: BillType[] = [...MOCK_BILL_TYPES];
let auditLogs: AuditLog[] = [];

const getEditableMonths = (): string[] => {
  const months = [];
  const date = new Date();
  const monthNames = ["January", "February", "March", "April", "May", "June", "July", "August", "September", "October", "November", "December"];
  for (let i = 0; i < 3; i++) {
    const d = new Date(date.getFullYear(), date.getMonth() - i, 1);
    months.push(`${monthNames[d.getMonth()]} ${d.getFullYear()}`);
  }
  return months;
};

export const api = {
  getBillTypes: async () => [...billTypes],

  getProperties: async () => [...properties],

  getBills: async () => [...bills],

  // Super Admin: Create/Update Bill Type in Dictionary
  upsertBillType: async (user: User, billType: Partial<BillType>) => {
    if (user.role !== 'SUPER_ADMIN') throw new Error('Unauthorized');

    if (billType.id) {
      // Update
      const idx = billTypes.findIndex(bt => bt.id === billType.id);
      if (idx !== -1) {
        billTypes[idx] = { ...billTypes[idx], ...billType } as BillType;
      }
    } else {
      // Create
      const newType: BillType = {
        id: `bt-${Date.now()}`,
        name: billType.name || 'New Utility',
        icon: billType.icon || 'fa-file-invoice',
        requiresAmount: billType.requiresAmount ?? true,
        requiresAttachment: billType.requiresAttachment ?? false,
      };
      billTypes.push(newType);
    }
    return [...billTypes];
  },

  // Super Admin: Delete Bill Type
  deleteBillType: async (user: User, billTypeId: string) => {
    if (user.role !== 'SUPER_ADMIN') throw new Error('Unauthorized');
    billTypes = billTypes.filter(bt => bt.id !== billTypeId);
    // Remove from properties
    properties = properties.map(p => ({
      ...p,
      activeBillTypeIds: p.activeBillTypeIds.filter(id => id !== billTypeId)
    }));
    return [...billTypes];
  },

  // Super Admin: Update property bill config
  updatePropertyConfig: async (user: User, propertyId: string, billTypeIds: string[]) => {
    if (user.role !== 'SUPER_ADMIN') throw new Error('Unauthorized');
    properties = properties.map(p => p.id === propertyId ? { ...p, activeBillTypeIds: billTypeIds } : p);
    return [...properties];
  },

  addProperty: async (user: User, name: string, address: string, activeBillTypeIds: string[]): Promise<Property> => {
    if (user.role !== 'SUPER_ADMIN') throw new Error('Unauthorized');
    const newProp: Property = {
      id: `p${Date.now()}`,
      name,
      address,
      activeBillTypeIds: activeBillTypeIds
    };
    properties = [...properties, newProp];
    return newProp;
  },

  // Admin: Submit a new bill entry
  submitBillEntry: async (user: User, entry: Partial<Bill>) => {
    if (user.role !== 'ADMIN') throw new Error('Unauthorized');
    const newBill: Bill = {
      id: `b${Date.now()}`,
      propertyId: entry.propertyId!,
      billTypeId: entry.billTypeId!,
      month: entry.month!,
      amount: entry.amount,
      attachmentName: entry.attachmentName,
      status: BillStatus.UNPAID,
      updatedAt: new Date().toISOString()
    };
    bills = [...bills, newBill];
    return newBill;
  },

  updateBillStatus: async (user: User, billId: string, newStatus: BillStatus): Promise<Bill> => {
    if (user.role !== 'ADMIN') throw new Error('Unauthorized');
    const idx = bills.findIndex(b => b.id === billId);
    if (idx === -1) throw new Error('Bill not found');

    const bill = bills[idx];
    if (!getEditableMonths().includes(bill.month)) throw new Error('Month Locked');

    const oldStatus = bill.status;
    const updated = { ...bill, status: newStatus, updatedAt: new Date().toISOString() };

    const prop = properties.find(p => p.id === bill.propertyId);
    const bt = billTypes.find(t => t.id === bill.billTypeId);

    auditLogs = [{
      id: `log-${Date.now()}`,
      propertyId: bill.propertyId,
      propertyName: prop?.name || 'Unknown',
      billType: bt?.name || 'Unknown',
      billMonth: bill.month,
      oldStatus,
      newStatus,
      updatedBy: user.name,
      updatedById: user.id,
      timestamp: new Date().toISOString()
    }, ...auditLogs];

    bills[idx] = updated;
    return updated;
  },

  getAuditLogs: async (user: User) => {
    if (user.role !== 'SUPER_ADMIN') throw new Error('Unauthorized');
    return [...auditLogs];
  }
};

import React, { useState, useEffect } from 'react';
import Layout from './components/Layout';
import SuperAdminView from './components/SuperAdminView';
import AdminView from './components/AdminView';
import { User, Property, Bill, BillStatus, UserRole, AuditLog } from './types';
import { authService } from './services/authService';
import { api } from './services/api';
import { MOCK_USERS } from './services/mockData';

const App: React.FC = () => {
  const [user, setUser] = useState<User | null>(null);
  const [properties, setProperties] = useState<Property[]>([]);
  const [bills, setBills] = useState<Bill[]>([]);
  const [auditLogs, setAuditLogs] = useState<AuditLog[]>([]);
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [error, setError] = useState('');
  const [isLoggingIn, setIsLoggingIn] = useState(false);
  const [isLoading, setIsLoading] = useState(false);

  useEffect(() => {
    const fetchData = async () => {
      try {
        const [props, b] = await Promise.all([api.getProperties(), api.getBills()]);
        setProperties(props);
        setBills(b);
      } catch (err) {
        console.error("Initialization failed", err);
      }
    };
    fetchData();
  }, []);

  const handleLogin = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsLoggingIn(true);
    setError('');
    try {
      const authenticatedUser = await authService.login(email, password);
      setUser(authenticatedUser as User);
      if (authenticatedUser.role === 'SUPER_ADMIN') {
        const logs = await api.getAuditLogs(authenticatedUser as User);
        setAuditLogs(logs);
      }
    } catch (err: any) {
      setError(err.message || 'An error occurred during login');
    } finally {
      setIsLoggingIn(false);
    }
  };

  const handleLogout = () => {
    setUser(null);
    setEmail('');
    setPassword('');
    setError('');
  };

  const handleAddProperty = async (name: string, address: string, activeBillTypeIds: string[]) => {
    if (!user) return;
    try {
      setIsLoading(true);
      const newProp = await api.addProperty(user, name, address, activeBillTypeIds);
      setProperties(prev => [...prev, newProp]);
    } catch (err: any) {
      alert(err.message);
    } finally {
      setIsLoading(false);
    }
  };

  const updateBillStatus = async (billId: string, newStatus: BillStatus) => {
    if (!user) return;
    try {
      setIsLoading(true);
      const updatedBill = await api.updateBillStatus(user, billId, newStatus);
      setBills(prev => prev.map(b => b.id === billId ? updatedBill : b));
      if (user.role === 'SUPER_ADMIN') {
        const logs = await api.getAuditLogs(user);
        setAuditLogs(logs);
      }
    } catch (err: any) {
      alert(err.message);
    } finally {
      setIsLoading(false);
    }
  };

  const fillDemoCredentials = (role: UserRole) => {
    const demoUser = MOCK_USERS.find(u => u.role === role);
    if (demoUser) {
      setEmail(demoUser.email);
      setPassword(demoUser.password || 'password123');
    }
  };

  if (!user) {
    return (
      <div className="min-h-screen flex items-center justify-center bg-slate-50 px-4 relative overflow-hidden">
        <div className="max-w-md w-full bg-white rounded-[3rem] shadow-2xl p-10 border border-slate-100 relative z-10">
          <div className="flex flex-col items-center mb-10 text-center">
            <div className="w-16 h-16 bg-blue-600 rounded-2xl mb-4 shadow-xl flex items-center justify-center text-white text-3xl">
              <i className="fas fa-bolt"></i>
            </div>
            <h1 className="text-2xl font-black text-slate-800 tracking-tight">ElectraFlow</h1>
            <p className="text-slate-400 mt-1 font-black uppercase tracking-widest text-[8px]">Multi-Utility Management</p>
          </div>
          <form onSubmit={handleLogin} className="space-y-4">
            <input type="email" value={email} onChange={(e) => setEmail(e.target.value)} placeholder="Email" className="w-full px-5 py-4 bg-slate-50 border rounded-2xl font-bold" required />
            <input type="password" value={password} onChange={(e) => setPassword(e.target.value)} placeholder="Password" className="w-full px-5 py-4 bg-slate-50 border rounded-2xl font-bold" required />
            {error && <div className="text-[10px] font-black text-rose-600 uppercase text-center">{error}</div>}
            <button type="submit" disabled={isLoggingIn} className="w-full bg-slate-900 text-white font-black py-4 rounded-2xl uppercase tracking-widest text-xs">Sign In</button>
          </form>
          <div className="mt-8 pt-6 border-t flex flex-wrap justify-center gap-4">
            <button onClick={() => fillDemoCredentials('SUPER_ADMIN')} className="text-[9px] font-black text-blue-600 uppercase">Super Admin</button>
            <button onClick={() => fillDemoCredentials('ADMIN')} className="text-[9px] font-black text-slate-400 uppercase">Field Admin</button>
          </div>
        </div>
      </div>
    );
  }

  return (
    <Layout user={user} onLogout={handleLogout}>
      {isLoading && (
        <div className="fixed inset-0 bg-slate-900/10 backdrop-blur-[2px] z-[1000] flex items-center justify-center">
          <div className="w-12 h-12 border-4 border-blue-600 border-t-transparent rounded-full animate-spin"></div>
        </div>
      )}
      {user.role === 'SUPER_ADMIN' ? (
        <SuperAdminView properties={properties} bills={bills} onAddProperty={handleAddProperty} auditLogs={auditLogs} user={user} />
      ) : (
        <AdminView properties={properties} bills={bills} onUpdateStatus={updateBillStatus} user={user} />
      )}
    </Layout>
  );
};

export default App;

import React, { useState, useMemo, useEffect } from 'react';
import { Property, Bill, BillStatus, AuditLog, BillType } from '../types';
import { api } from '../services/api';

interface SuperAdminViewProps {
  properties: Property[];
  bills: Bill[];
  onAddProperty: (name: string, address: string, activeBillTypeIds: string[]) => void;
  auditLogs: AuditLog[];
  user: any;
}

const SuperAdminView: React.FC<SuperAdminViewProps> = ({ properties: initialProps, bills, onAddProperty, auditLogs, user }) => {
  const [activeTab, setActiveTab] = useState<'PORTFOLIO' | 'AUDIT' | 'CONFIG'>('PORTFOLIO');
  const [billTypes, setBillTypes] = useState<BillType[]>([]);
  const [properties, setProperties] = useState<Property[]>(initialProps);
  const [showAddProp, setShowAddProp] = useState(false);
  const [configPropId, setConfigPropId] = useState<string | null>(null);

  // Bill Dictionary State
  const [editingBillType, setEditingBillType] = useState<Partial<BillType> | null>(null);
  const [showBillTypeModal, setShowBillTypeModal] = useState(false);

  // New Property State
  const [selectedBillTypeIds, setSelectedBillTypeIds] = useState<string[]>([]);

  useEffect(() => {
    api.getBillTypes().then(setBillTypes);
  }, []);

  useEffect(() => {
    setProperties(initialProps);
  }, [initialProps]);

  const handleToggleBillForProp = async (propId: string, billTypeId: string) => {
    const prop = properties.find(p => p.id === propId);
    if (!prop) return;
    const current = prop.activeBillTypeIds;
    const updated = current.includes(billTypeId) 
      ? current.filter(id => id !== billTypeId) 
      : [...current, billTypeId];

    const updatedProps = await api.updatePropertyConfig(user, propId, updated);
    setProperties(updatedProps);
  };

  const handleSaveBillType = async (e: React.FormEvent) => {
    e.preventDefault();
    if (editingBillType) {
      const updatedTypes = await api.upsertBillType(user, editingBillType);
      setBillTypes(updatedTypes);
      setShowBillTypeModal(false);
      setEditingBillType(null);
    }
  };

  const handleDeleteBillType = async (id: string) => {
    if (confirm('Deleting this utility will remove it from all properties and existing history. Continue?')) {
      const updatedTypes = await api.deleteBillType(user, id);
      setBillTypes(updatedTypes);
      // Re-fetch properties as their activeBillTypeIds might have changed
      const updatedProps = await api.getProperties();
      setProperties(updatedProps);
    }
  };

  const handleAddPropSubmit = (e: React.FormEvent<HTMLFormElement>) => {
    e.preventDefault();
    const d = new FormData(e.currentTarget);
    onAddProperty(
      d.get('name') as string, 
      d.get('address') as string, 
      selectedBillTypeIds
    );
    setShowAddProp(false);
    setSelectedBillTypeIds([]);
  };

  const toggleBillSelection = (id: string) => {
    setSelectedBillTypeIds(prev => 
      prev.includes(id) ? prev.filter(i => i !== id) : [...prev, id]
    );
  };

  const currentMonth = useMemo(() => {
    const d = new Date();
    const monthNames = ["January", "February", "March", "April", "May", "June", "July", "August", "September", "October", "November", "December"];
    return `${monthNames[d.getMonth()]} ${d.getFullYear()}`;
  }, []);

  return (
    <div className="max-w-6xl mx-auto space-y-6 animate-fadeIn pb-20">
      <div className="flex flex-wrap gap-2 p-1 bg-slate-200/50 rounded-2xl w-fit">
        {['PORTFOLIO', 'AUDIT', 'CONFIG'].map(tab => (
          <button 
            key={tab}
            onClick={() => setActiveTab(tab as any)}
            className={`px-6 py-2 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all ${
              activeTab === tab ? 'bg-white shadow-sm text-slate-900' : 'text-slate-500 hover:bg-slate-200'
            }`}
          >
            {tab}
          </button>
        ))}
      </div>

      {activeTab === 'PORTFOLIO' && (
        <div className="space-y-6">
          <div className="grid grid-cols-1 sm:grid-cols-3 gap-4">
            <div className="bg-white p-6 rounded-[2rem] border border-slate-100 shadow-sm">
