                >
                  Create Asset
                </button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default SuperAdminView;

import React, { useState, useMemo, useEffect } from 'react';
import { Property, Bill, BillStatus, AuditLog, BillType } from '../types';
import { api } from '../services/api';

interface SuperAdminViewProps {
  properties: Property[];
  bills: Bill[];
  onAddProperty: (name: string, address: string, activeBillTypeIds: string[]) => void;
  auditLogs: AuditLog[];
  user: any;
}

const SuperAdminView: React.FC<SuperAdminViewProps> = ({ properties: initialProps, bills, onAddProperty, auditLogs, user }) => {
  const [activeTab, setActiveTab] = useState<'PORTFOLIO' | 'AUDIT' | 'CONFIG'>('PORTFOLIO');
  const [billTypes, setBillTypes] = useState<BillType[]>([]);
  const [properties, setProperties] = useState<Property[]>(initialProps);
  const [showAddProp, setShowAddProp] = useState(false);
  const [configPropId, setConfigPropId] = useState<string | null>(null);

  // Bill Dictionary State
  const [editingBillType, setEditingBillType] = useState<Partial<BillType> | null>(null);
  const [showBillTypeModal, setShowBillTypeModal] = useState(false);

  // New Property State
  const [selectedBillTypeIds, setSelectedBillTypeIds] = useState<string[]>([]);

  useEffect(() => {
    api.getBillTypes().then(setBillTypes);
  }, []);

  useEffect(() => {
    setProperties(initialProps);
  }, [initialProps]);

  const handleToggleBillForProp = async (propId: string, billTypeId: string) => {
    const prop = properties.find(p => p.id === propId);
    if (!prop) return;
    const current = prop.activeBillTypeIds;
    const updated = current.includes(billTypeId) 
      ? current.filter(id => id !== billTypeId) 
      : [...current, billTypeId];

    const updatedProps = await api.updatePropertyConfig(user, propId, updated);
    setProperties(updatedProps);
  };

  const handleSaveBillType = async (e: React.FormEvent) => {
    e.preventDefault();
    if (editingBillType) {
      const updatedTypes = await api.upsertBillType(user, editingBillType);
      setBillTypes(updatedTypes);
      setShowBillTypeModal(false);
      setEditingBillType(null);
    }
  };

  const handleDeleteBillType = async (id: string) => {
    if (confirm('Deleting this utility will remove it from all properties and existing history. Continue?')) {
      const updatedTypes = await api.deleteBillType(user, id);
      setBillTypes(updatedTypes);
      // Re-fetch properties as their activeBillTypeIds might have changed
      const updatedProps = await api.getProperties();
      setProperties(updatedProps);
    }
  };

  const handleAddPropSubmit = (e: React.FormEvent<HTMLFormElement>) => {
    e.preventDefault();
    const d = new FormData(e.currentTarget);
    const name = d.get('name') as string;
    const address = d.get('address') as string;

    if (!name || !address) return;

    onAddProperty(name, address, selectedBillTypeIds);
    setShowAddProp(false);
    setSelectedBillTypeIds([]);
  };

  const toggleBillSelection = (id: string) => {
    setSelectedBillTypeIds(prev => 
      prev.includes(id) ? prev.filter(i => i !== id) : [...prev, id]
    );
  };

  const currentMonth = useMemo(() => {
    const d = new Date();
    const monthNames = ["January", "February", "March", "April", "May", "June", "July", "August", "September", "October", "November", "December"];
    return `${monthNames[d.getMonth()]} ${d.getFullYear()}`;
  }, []);

  return (
    <div className="max-w-6xl mx-auto space-y-6 animate-fadeIn pb-20">
      <div className="flex flex-wrap gap-2 p-1 bg-slate-200/50 rounded-2xl w-fit">
        {['PORTFOLIO', 'AUDIT', 'CONFIG'].map(tab => (
          <button 
            key={tab}
            onClick={() => setActiveTab(tab as any)}
            className={`px-6 py-2 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all ${
              activeTab === tab ? 'bg-white shadow-sm text-slate-900' : 'text-slate-500 hover:bg-slate-200'
            }`}
          >
            {tab}
          </button>
        ))}
      </div>

      {activeTab === 'PORTFOLIO' && (
        <div className="space-y-6">
          <div className="grid grid-cols-1 sm:grid-cols-3 gap-4">
            <div className="bg-white p-6 rounded-[2rem] border border-slate-100 shadow-sm">
              <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1">Assets</p>
              <p className="text-3xl font-black text-slate-800">{properties.length}</p>
            </div>
            <div className="bg-white p-6 rounded-[2rem] border border-slate-100 shadow-sm">
              <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1">Active Utilities</p>
              <p className="text-3xl font-black text-blue-600">{billTypes.length}</p>
            </div>
            <button 
              onClick={() => {
                setSelectedBillTypeIds([]);
                setShowAddProp(true);
              }}
              className="bg-slate-900 text-white rounded-[2rem] p-6 font-black uppercase text-xs tracking-widest hover:bg-black transition-all"
            >
              Add New Property
            </button>
          </div>

          <div className="bg-white rounded-[2.5rem] border border-slate-100 shadow-xl overflow-hidden">
            <table className="w-full text-left">
              <thead>
                <tr className="text-[10px] font-black text-slate-400 uppercase tracking-widest bg-slate-50/50">
                  <th className="px-8 py-5">Property</th>
                  <th className="px-8 py-5">Active Utilities</th>
                  <th className="px-8 py-5 text-right">Actions</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-slate-50">
                {properties.map(p => (
                  <tr key={p.id} className="hover:bg-slate-50 transition-all">
                    <td className="px-8 py-6">
                      <div className="font-bold text-slate-800">{p.name}</div>
                      <div className="text-[9px] text-slate-400 font-bold uppercase">{p.address}</div>
                    </td>
                    <td className="px-8 py-6">
                      <div className="flex flex-wrap gap-2">
                        {p.activeBillTypeIds.map(btId => {
                          const bt = billTypes.find(t => t.id === btId);
                          return (
                            <span key={btId} className="px-2 py-1 bg-blue-50 text-blue-600 text-[8px] font-black rounded-lg uppercase flex items-center gap-1">
                              <i className={`fas ${bt?.icon || 'fa-bolt'} text-[10px]`}></i>
                              {bt?.name}
                            </span>
                          );
                        })}
                        {p.activeBillTypeIds.length === 0 && <span className="text-slate-300 italic text-[9px]">None configured</span>}
                      </div>
                    </td>
                    <td className="px-8 py-6 text-right">
                      <button 
                        onClick={() => setConfigPropId(p.id)}
                        className="text-slate-400 hover:text-blue-600 font-black uppercase text-[10px] tracking-widest bg-slate-50 px-4 py-2 rounded-xl transition-all"
                      >
                        Edit Config
                      </button>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </div>
      )}

      {activeTab === 'CONFIG' && (
        <div className="bg-white rounded-[2.5rem] border border-slate-100 shadow-xl p-10 space-y-8">
          <div className="flex justify-between items-center">
            <div>
              <h2 className="text-2xl font-black text-slate-800">Global Bill Dictionary</h2>
              <p className="text-slate-400 text-xs font-bold uppercase tracking-widest">Master list of all utilities</p>
            </div>
            <button 
              onClick={() => {
                setEditingBillType({ name: '', icon: 'fa-file-invoice', requiresAmount: true, requiresAttachment: false });
                setShowBillTypeModal(true);
              }}
              className="bg-blue-600 hover:bg-blue-700 text-white px-6 py-3 rounded-2xl font-black text-xs uppercase tracking-widest shadow-xl transition-all flex items-center gap-2"
            >
              <i className="fas fa-plus"></i>
              Add New Type
            </button>
          </div>
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
            {billTypes.map(bt => (
              <div key={bt.id} className="p-6 bg-slate-50 rounded-3xl border border-slate-100 space-y-4 relative group">
                <div className="absolute top-4 right-4 flex gap-2 opacity-0 group-hover:opacity-100 transition-all">
                   <button 
                    onClick={() => { setEditingBillType(bt); setShowBillTypeModal(true); }}
                    className="w-8 h-8 bg-white border border-slate-100 rounded-lg flex items-center justify-center text-slate-400 hover:text-blue-600 shadow-sm"
                   >
                    <i className="fas fa-pen text-[10px]"></i>
                   </button>
                   <button 
                    onClick={() => handleDeleteBillType(bt.id)}
                    className="w-8 h-8 bg-white border border-slate-100 rounded-lg flex items-center justify-center text-slate-400 hover:text-rose-600 shadow-sm"
                   >
                    <i className="fas fa-trash text-[10px]"></i>
                   </button>
                </div>

                <div className="flex items-center gap-3">
                  <div className="w-12 h-12 bg-white rounded-2xl flex items-center justify-center text-blue-600 shadow-sm border border-slate-100 text-xl">
                    <i className={`fas ${bt.icon}`}></i>
                  </div>
                  <span className="font-black text-slate-800 text-lg">{bt.name}</span>
                </div>
                <div className="space-y-2 pt-2 border-t border-slate-100/50">
                  <div className="flex items-center justify-between">
                    <span className="text-[10px] font-bold text-slate-500 uppercase">Numerical Amount</span>
                    <span className={`text-[9px] font-black px-2 py-1 rounded-lg ${bt.requiresAmount ? 'bg-emerald-50 text-emerald-600 border border-emerald-100' : 'bg-slate-200 text-slate-400'}`}>
                      {bt.requiresAmount ? 'MANDATORY' : 'OPTIONAL'}
                    </span>
                  </div>
                  <div className="flex items-center justify-between">
                    <span className="text-[10px] font-bold text-slate-500 uppercase">Document Proof</span>
                    <span className={`text-[9px] font-black px-2 py-1 rounded-lg ${bt.requiresAttachment ? 'bg-emerald-50 text-emerald-600 border border-emerald-100' : 'bg-slate-200 text-slate-400'}`}>
                      {bt.requiresAttachment ? 'MANDATORY' : 'NONE'}
                    </span>
                  </div>
                </div>
              </div>
            ))}
          </div>
        </div>
      )}

      {activeTab === 'AUDIT' && (
        <div className="bg-white rounded-[2.5rem] border border-slate-100 shadow-xl overflow-hidden">
          <table className="w-full text-left text-xs">
            <thead>
              <tr className="text-[9px] font-black text-slate-400 uppercase tracking-widest bg-slate-50/50">
                <th className="px-6 py-5">Time</th>
                <th className="px-6 py-5">Operator</th>
                <th className="px-6 py-5">Target</th>
                <th className="px-6 py-5">Utility</th>
                <th className="px-6 py-5">Change</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-50">
              {auditLogs.length === 0 ? (
                <tr>
                   <td colSpan={5} className="px-6 py-20 text-center text-slate-300 font-black uppercase tracking-widest text-[10px]">No activity logs detected</td>
                </tr>
              ) : auditLogs.map(log => (
                <tr key={log.id} className="hover:bg-slate-50/50 transition-colors">
                  <td className="px-6 py-4 text-slate-400">{new Date(log.timestamp).toLocaleTimeString()}</td>
                  <td className="px-6 py-4 font-bold">{log.updatedBy}</td>
                  <td className="px-6 py-4">{log.propertyName}</td>
                  <td className="px-6 py-4 text-blue-600 font-black">{log.billType}</td>
                  <td className="px-6 py-4">
                    <div className="flex items-center gap-1 font-black">
                      <span className={log.oldStatus === 'PAID' ? 'text-emerald-500' : 'text-rose-500'}>{log.oldStatus}</span>
                      <i className="fas fa-arrow-right text-[8px] opacity-30"></i>
                      <span className={log.newStatus === 'PAID' ? 'text-emerald-500' : 'text-rose-500'}>{log.newStatus}</span>
                    </div>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      )}

      {/* Bill Type Upsert Modal */}
      {showBillTypeModal && (
        <div className="fixed inset-0 bg-slate-900/40 backdrop-blur-sm z-[300] flex items-center justify-center p-4">
          <div className="bg-white rounded-[3rem] shadow-2xl w-full max-w-md p-10 animate-scaleUp">
            <h2 className="text-2xl font-black text-slate-800 mb-6">{editingBillType?.id ? 'Edit Utility' : 'New Utility Type'}</h2>
            <form onSubmit={handleSaveBillType} className="space-y-6">
              <div className="space-y-2">
                <label className="text-[10px] font-black text-slate-400 uppercase px-2">Name</label>
                <input 
                  required autoFocus
                  className="w-full p-4 bg-slate-50 border border-slate-100 rounded-2xl font-bold outline-none focus:ring-4 focus:ring-blue-500/10 transition-all"
                  value={editingBillType?.name || ''}
                  onChange={e => setEditingBillType({ ...editingBillType!, name: e.target.value })}
                  placeholder="e.g., Gas, Parking, Maintenance"
                />
              </div>
              <div className="space-y-2">
                <label className="text-[10px] font-black text-slate-400 uppercase px-2">Icon (FontAwesome Class)</label>
                <input 
                  required
                  className="w-full p-4 bg-slate-50 border border-slate-100 rounded-2xl font-bold outline-none"
                  value={editingBillType?.icon || ''}
                  onChange={e => setEditingBillType({ ...editingBillType!, icon: e.target.value })}
                  placeholder="fa-bolt, fa-water, etc."
                />
              </div>
              <div className="grid grid-cols-2 gap-4">
                <button 
                  type="button"
                  onClick={() => setEditingBillType({ ...editingBillType!, requiresAmount: !editingBillType?.requiresAmount })}
                  className={`p-4 rounded-2xl border-2 transition-all flex flex-col items-center gap-2 ${editingBillType?.requiresAmount ? 'bg-blue-50 border-blue-500 text-blue-700' : 'bg-slate-50 border-slate-100 text-slate-400'}`}
                >
                  <i className="fas fa-calculator text-lg"></i>
                  <span className="text-[9px] font-black uppercase">Amount Required</span>
                </button>
                <button 
                  type="button"
                  onClick={() => setEditingBillType({ ...editingBillType!, requiresAttachment: !editingBillType?.requiresAttachment })}
                  className={`p-4 rounded-2xl border-2 transition-all flex flex-col items-center gap-2 ${editingBillType?.requiresAttachment ? 'bg-blue-50 border-blue-500 text-blue-700' : 'bg-slate-50 border-slate-100 text-slate-400'}`}
                >
                  <i className="fas fa-file-pdf text-lg"></i>
                  <span className="text-[9px] font-black uppercase">Attach File</span>
                </button>
              </div>
              <div className="flex gap-4 pt-4">
                <button type="button" onClick={() => setShowBillTypeModal(false)} className="flex-1 py-4 text-slate-400 font-black uppercase text-[10px] tracking-widest">Cancel</button>
                <button type="submit" className="flex-1 py-4 bg-blue-600 text-white rounded-2xl font-black uppercase text-[10px] tracking-widest shadow-xl">Save Type</button>
              </div>
            </form>
          </div>
        </div>
      )}

      {/* Property Configuration Modal (FOR EXISTING PROPERTIES) */}
      {configPropId && (
        <div className="fixed inset-0 bg-slate-900/40 backdrop-blur-sm z-[200] flex items-center justify-center p-4">
          <div className="bg-white rounded-[3rem] shadow-2xl w-full max-w-md p-10 animate-scaleUp">
            <h2 className="text-2xl font-black text-slate-800 mb-2">Configure Utilities</h2>
            <p className="text-slate-400 text-xs font-bold uppercase tracking-widest mb-6">
              {properties.find(p => p.id === configPropId)?.name}
            </p>
            <div className="space-y-3 max-h-[50vh] overflow-y-auto px-1">
              {billTypes.map(bt => (
                <button 
                  key={bt.id}
                  onClick={() => handleToggleBillForProp(configPropId, bt.id)}
                  className={`w-full flex items-center justify-between p-4 rounded-2xl border-2 transition-all ${
                    properties.find(p => p.id === configPropId)?.activeBillTypeIds.includes(bt.id)
                    ? 'bg-blue-50 border-blue-500 text-blue-700 shadow-md shadow-blue-500/10'
                    : 'bg-slate-50 border-slate-100 text-slate-400'
                  }`}
                >
                  <div className="flex items-center gap-3">
                    <div className={`w-8 h-8 rounded-lg flex items-center justify-center ${properties.find(p => p.id === configPropId)?.activeBillTypeIds.includes(bt.id) ? 'bg-white' : 'bg-slate-100'}`}>
                      <i className={`fas ${bt.icon}`}></i>
                    </div>
                    <span className="font-bold">{bt.name}</span>
                  </div>
                  <i className={`fas ${properties.find(p => p.id === configPropId)?.activeBillTypeIds.includes(bt.id) ? 'fa-check-circle text-blue-500' : 'fa-circle-notch opacity-20'}`}></i>
                </button>
              ))}
              {billTypes.length === 0 && <div className="p-8 text-center text-slate-300 font-bold uppercase text-[10px]">No utilities defined in dictionary</div>}
            </div>
            <button 
              onClick={() => setConfigPropId(null)}
              className="w-full mt-8 py-4 bg-slate-900 text-white rounded-2xl font-black uppercase text-[10px] tracking-widest shadow-xl hover:bg-black transition-all"
            >
              Close Config
            </button>
          </div>
        </div>
      )}

      {/* NEW PROPERTY MODAL - FIXED CREATE BUTTON */}
      {showAddProp && (
        <div className="fixed inset-0 bg-slate-900/40 backdrop-blur-sm z-[200] flex items-center justify-center p-4">
          <div className="bg-white rounded-[3rem] shadow-2xl w-full max-w-lg p-10 animate-scaleUp overflow-hidden flex flex-col max-h-[90vh]">
            <div className="flex justify-between items-center mb-6">
               <h2 className="text-2xl font-black text-slate-800">New Property Setup</h2>
               <button onClick={() => setShowAddProp(false)} className="text-slate-400 hover:text-slate-600">
                  <i className="fas fa-times text-lg"></i>
               </button>
            </div>

            <form onSubmit={handleAddPropSubmit} className="space-y-6 flex flex-col overflow-hidden">
              <div className="space-y-4">
                <div className="space-y-1">
                  <label className="text-[10px] font-black text-slate-400 uppercase px-2">Asset Details</label>
                  <input name="name" required placeholder="Asset Name (e.g., Block A)" className="w-full p-4 bg-slate-50 border border-slate-100 rounded-2xl font-bold outline-none focus:ring-4 focus:ring-blue-500/10 transition-all" />
                </div>
                <div className="space-y-1">
                  <input name="address" required placeholder="Physical Address" className="w-full p-4 bg-slate-50 border border-slate-100 rounded-2xl font-bold outline-none focus:ring-4 focus:ring-blue-500/10 transition-all" />
                </div>
              </div>

              <div className="flex-1 overflow-hidden flex flex-col space-y-2">
                <label className="text-[10px] font-black text-slate-400 uppercase px-2">Enable Utilities (Optional now)</label>
                <div className="flex-1 overflow-y-auto space-y-2 pr-1 custom-scrollbar">
                  {billTypes.map(bt => (
                    <button 
                      key={bt.id}
                      type="button"
                      onClick={() => toggleBillSelection(bt.id)}
                      className={`w-full flex items-center justify-between p-4 rounded-2xl border-2 transition-all group ${
                        selectedBillTypeIds.includes(bt.id)
                        ? 'bg-blue-50 border-blue-500 text-blue-700'
                        : 'bg-slate-50 border-slate-100 text-slate-400 hover:border-slate-300'
                      }`}
                    >
                      <div className="flex items-center gap-3">
                        <div className={`w-10 h-10 rounded-xl flex items-center justify-center ${selectedBillTypeIds.includes(bt.id) ? 'bg-white shadow-sm' : 'bg-slate-100'}`}>
                          <i className={`fas ${bt.icon}`}></i>
                        </div>
                        <span className="font-bold">{bt.name}</span>
                      </div>

                      {/* Using a radio-style selection indicator as requested */}
                      <div className={`w-6 h-6 rounded-full border-2 flex items-center justify-center transition-all ${
                        selectedBillTypeIds.includes(bt.id) ? 'border-blue-500 bg-white' : 'border-slate-300'
                      }`}>
                        {selectedBillTypeIds.includes(bt.id) && <div className="w-3 h-3 bg-blue-500 rounded-full animate-scaleIn"></div>}
                      </div>
                    </button>
                  ))}
                  {billTypes.length === 0 && (
                    <div className="p-8 text-center text-slate-300 bg-slate-50 rounded-2xl border border-dashed border-slate-200">
                      <p className="font-black uppercase text-[10px]">Dictionary is Empty</p>
                      <p className="text-[8px] mt-1">Go to 'Config' tab to define utilities</p>
                    </div>
                  )}
                </div>
              </div>

              <div className="flex gap-4 pt-4 bg-white">
                <button type="button" onClick={() => setShowAddProp(false)} className="flex-1 py-4 text-slate-400 font-black uppercase text-[10px] tracking-widest hover:text-slate-600 transition-colors">Discard</button>
                <button 
                  type="submit" 
                  className="flex-1 py-4 bg-blue-600 text-white rounded-2xl font-black uppercase text-[10px] tracking-widest shadow-xl hover:bg-blue-700 active:scale-[0.98] transition-all"
                >
                  Create Asset
                </button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default SuperAdminView;

import React, { useState, useMemo, useEffect } from 'react';
import { Property, Bill, BillStatus, AuditLog, BillType } from '../types';
import { api } from '../services/api';

interface SuperAdminViewProps {
  properties: Property[];
  bills: Bill[];
  onAddProperty: (name: string, address: string, activeBillTypeIds: string[]) => void;
  auditLogs: AuditLog[];
  user: any;
}

const SuperAdminView: React.FC<SuperAdminViewProps> = ({ properties: initialProps, bills: initialBills, onAddProperty, auditLogs, user }) => {
  const [activeTab, setActiveTab] = useState<'PORTFOLIO' | 'AUDIT' | 'CONFIG'>('PORTFOLIO');
  const [billTypes, setBillTypes] = useState<BillType[]>([]);
  const [properties, setProperties] = useState<Property[]>(initialProps);
  const [bills, setBills] = useState<Bill[]>(initialBills);
  const [showAddProp, setShowAddProp] = useState(false);
  const [configPropId, setConfigPropId] = useState<string | null>(null);
  const [viewingPropId, setViewingPropId] = useState<string | null>(null);

  // Bill Dictionary State
  const [editingBillType, setEditingBillType] = useState<Partial<BillType> | null>(null);
  const [showBillTypeModal, setShowBillTypeModal] = useState(false);

  // New Property State
  const [selectedBillTypeIds, setSelectedBillTypeIds] = useState<string[]>([]);

  useEffect(() => {
    api.getBillTypes().then(setBillTypes);
  }, []);

  useEffect(() => {
    setProperties(initialProps);
  }, [initialProps]);

  useEffect(() => {
    setBills(initialBills);
  }, [initialBills]);

  const handleToggleBillForProp = async (propId: string, billTypeId: string) => {
    const prop = properties.find(p => p.id === propId);
    if (!prop) return;
    const current = prop.activeBillTypeIds;
    const updated = current.includes(billTypeId) 
      ? current.filter(id => id !== billTypeId) 
      : [...current, billTypeId];

    const updatedProps = await api.updatePropertyConfig(user, propId, updated);
    setProperties(updatedProps);
  };

  const handleSaveBillType = async (e: React.FormEvent) => {
    e.preventDefault();
    if (editingBillType) {
      const updatedTypes = await api.upsertBillType(user, editingBillType);
      setBillTypes(updatedTypes);
      setShowBillTypeModal(false);
      setEditingBillType(null);
    }
  };

  const handleDeleteBillType = async (id: string) => {
    if (confirm('Deleting this utility will remove it from all properties and existing history. Continue?')) {
      const updatedTypes = await api.deleteBillType(user, id);
      setBillTypes(updatedTypes);
      const updatedProps = await api.getProperties();
      setProperties(updatedProps);
    }
  };

  const handleAddPropSubmit = (e: React.FormEvent<HTMLFormElement>) => {
    e.preventDefault();
    const d = new FormData(e.currentTarget);
    const name = d.get('name') as string;
    const address = d.get('address') as string;

    if (!name || !address) return;

    onAddProperty(name, address, selectedBillTypeIds);
    setShowAddProp(false);
    setSelectedBillTypeIds([]);
  };

  const toggleBillSelection = (id: string) => {
    setSelectedBillTypeIds(prev => 
      prev.includes(id) ? prev.filter(i => i !== id) : [...prev, id]
    );
  };

  // Logic to group bills by month for a specific property
  const getGroupedBills = (propId: string) => {
    const prop = properties.find(p => p.id === propId);
    if (!prop) return [];

    const propBills = bills.filter(b => b.propertyId === propId);
    const months = Array.from(new Set(propBills.map(b => b.month)));

    // Sort months descending (assuming Month Year format)
    months.sort((a, b) => new Date(b).getTime() - new Date(a).getTime());

    return months.map(m => {
      const billsInMonth = propBills.filter(b => b.month === m);
      return {
        month: m,
        utilityStatuses: prop.activeBillTypeIds.map(btId => {
          const bt = billTypes.find(t => t.id === btId);
          const bill = billsInMonth.find(b => b.billTypeId === btId);
          return {
            type: bt?.name || 'Unknown',
            icon: bt?.icon || 'fa-bolt',
            status: bill?.status || 'NOT RECORDED',
            amount: bill?.amount,
            billId: bill?.id
          };
        })
      };
    });
  };

  return (
    <div className="max-w-6xl mx-auto space-y-6 animate-fadeIn pb-20">
      <div className="flex flex-wrap gap-2 p-1 bg-slate-200/50 rounded-2xl w-fit">
        {['PORTFOLIO', 'AUDIT', 'CONFIG'].map(tab => (
          <button 
            key={tab}
            onClick={() => setActiveTab(tab as any)}
            className={`px-6 py-2 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all ${
              activeTab === tab ? 'bg-white shadow-sm text-slate-900' : 'text-slate-500 hover:bg-slate-200'
            }`}
          >
            {tab}
          </button>
        ))}
      </div>

      {activeTab === 'PORTFOLIO' && (
        <div className="space-y-6">
          <div className="grid grid-cols-1 sm:grid-cols-3 gap-4">
            <div className="bg-white p-6 rounded-[2rem] border border-slate-100 shadow-sm">
              <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1">Assets</p>
              <p className="text-3xl font-black text-slate-800">{properties.length}</p>
            </div>
            <div className="bg-white p-6 rounded-[2rem] border border-slate-100 shadow-sm">
              <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1">Active Utilities</p>
              <p className="text-3xl font-black text-blue-600">{billTypes.length}</p>
            </div>
            <button 
              onClick={() => {
                setSelectedBillTypeIds([]);
                setShowAddProp(true);
              }}
              className="bg-slate-900 text-white rounded-[2rem] p-6 font-black uppercase text-xs tracking-widest hover:bg-black transition-all"
            >
              Add New Property
            </button>
          </div>

          <div className="bg-white rounded-[2.5rem] border border-slate-100 shadow-xl overflow-hidden">
            <table className="w-full text-left">
              <thead>
                <tr className="text-[10px] font-black text-slate-400 uppercase tracking-widest bg-slate-50/50">
                  <th className="px-8 py-5">Property</th>
                  <th className="px-8 py-5">Active Utilities</th>
                  <th className="px-8 py-5 text-right">Actions</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-slate-50">
                {properties.map(p => (
                  <tr key={p.id} className="hover:bg-slate-50 transition-all group">
                    <td 
                      className="px-8 py-6 cursor-pointer"
                      onClick={() => setViewingPropId(p.id)}
                    >
                      <div className="font-bold text-slate-800 group-hover:text-blue-600 transition-colors">{p.name}</div>
                      <div className="text-[9px] text-slate-400 font-bold uppercase">{p.address}</div>
                    </td>
                    <td className="px-8 py-6">
                      <div className="flex flex-wrap gap-2">
                        {p.activeBillTypeIds.map(btId => {
                          const bt = billTypes.find(t => t.id === btId);
                          return (
                            <span key={btId} className="px-2 py-1 bg-blue-50 text-blue-600 text-[8px] font-black rounded-lg uppercase flex items-center gap-1">
                              <i className={`fas ${bt?.icon || 'fa-bolt'} text-[10px]`}></i>
                              {bt?.name}
                            </span>
                          );
                        })}
                        {p.activeBillTypeIds.length === 0 && <span className="text-slate-300 italic text-[9px]">None configured</span>}
                      </div>
                    </td>
                    <td className="px-8 py-6 text-right">
                      <button 
                        onClick={() => setConfigPropId(p.id)}
                        className="text-slate-400 hover:text-blue-600 font-black uppercase text-[10px] tracking-widest bg-slate-50 px-4 py-2 rounded-xl transition-all"
                      >
                        Edit Config
                      </button>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </div>
      )}

      {/* PROPERTY BILL HISTORY MODAL */}
      {viewingPropId && (
        <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-md z-[250] flex items-center justify-center p-4">
          <div className="bg-white rounded-[3rem] shadow-2xl w-full max-w-2xl p-8 animate-scaleUp overflow-hidden flex flex-col max-h-[85vh]">
            <div className="flex justify-between items-start mb-6">
              <div>
                <h2 className="text-2xl font-black text-slate-800">Bill History</h2>
                <p className="text-slate-400 text-[10px] font-bold uppercase tracking-widest">
                  {properties.find(p => p.id === viewingPropId)?.name}
                </p>
              </div>
              <button onClick={() => setViewingPropId(null)} className="w-10 h-10 rounded-full hover:bg-slate-100 flex items-center justify-center text-slate-400">
                <i className="fas fa-times"></i>
              </button>
            </div>

            <div className="flex-1 overflow-y-auto pr-2 custom-scrollbar">
              {getGroupedBills(viewingPropId).length === 0 ? (
                <div className="py-20 text-center">
                  <div className="w-16 h-16 bg-slate-50 rounded-2xl mx-auto flex items-center justify-center text-slate-200 mb-4">
                    <i className="fas fa-history text-2xl"></i>
                  </div>
                  <p className="text-slate-400 font-black uppercase text-[10px] tracking-widest">No billing records found</p>
                </div>
              ) : (
                <div className="space-y-8">
                  {getGroupedBills(viewingPropId).map(group => (
                    <div key={group.month} className="space-y-3">
                      <h4 className="text-[10px] font-black text-slate-400 uppercase tracking-[0.2em] sticky top-0 bg-white py-2 z-10 border-b border-slate-50">
                        {group.month}
                      </h4>
                      <div className="grid grid-cols-1 gap-2">
                        {group.utilityStatuses.map((util, idx) => (
                          <div key={idx} className="flex items-center justify-between p-4 bg-slate-50 rounded-2xl border border-slate-100">
                            <div className="flex items-center gap-3">
                              <div className="w-10 h-10 bg-white rounded-xl flex items-center justify-center text-blue-600 shadow-sm border border-slate-100">
                                <i className={`fas ${util.icon}`}></i>
                              </div>
                              <div>
                                <div className="font-bold text-slate-700 text-sm">{util.type}</div>
                                {util.amount && <div className="text-[10px] font-bold text-slate-400">${util.amount}</div>}
                              </div>
                            </div>
                            <span className={`text-[9px] font-black px-3 py-1.5 rounded-full uppercase tracking-widest border ${
                              util.status === 'PAID' ? 'bg-emerald-50 text-emerald-600 border-emerald-100' : 
                              util.status === 'UNPAID' ? 'bg-rose-50 text-rose-600 border-rose-100' : 
                              'bg-slate-100 text-slate-400 border-slate-200'
                            }`}>
                              {util.status}
                            </span>
                          </div>
                        ))}
                      </div>
                    </div>
                  ))}
                </div>
              )}
            </div>

            <button 
              onClick={() => setViewingPropId(null)}
              className="w-full mt-6 py-4 bg-slate-900 text-white rounded-2xl font-black uppercase text-[10px] tracking-widest shadow-xl"
            >
              Close History
            </button>
          </div>
        </div>
      )}

      {activeTab === 'CONFIG' && (
        <div className="bg-white rounded-[2.5rem] border border-slate-100 shadow-xl p-10 space-y-8">
          <div className="flex justify-between items-center">
            <div>
              <h2 className="text-2xl font-black text-slate-800">Global Bill Dictionary</h2>
              <p className="text-slate-400 text-xs font-bold uppercase tracking-widest">Master list of all utilities</p>
            </div>
            <button 
              onClick={() => {
                setEditingBillType({ name: '', icon: 'fa-file-invoice', requiresAmount: true, requiresAttachment: false });
                setShowBillTypeModal(true);
              }}
              className="bg-blue-600 hover:bg-blue-700 text-white px-6 py-3 rounded-2xl font-black text-xs uppercase tracking-widest shadow-xl transition-all flex items-center gap-2"
            >
              <i className="fas fa-plus"></i>
              Add New Type
            </button>
          </div>
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
            {billTypes.map(bt => (
              <div key={bt.id} className="p-6 bg-slate-50 rounded-3xl border border-slate-100 space-y-4 relative group">
                <div className="absolute top-4 right-4 flex gap-2 opacity-0 group-hover:opacity-100 transition-all">
                   <button 
                    onClick={() => { setEditingBillType(bt); setShowBillTypeModal(true); }}
                    className="w-8 h-8 bg-white border border-slate-100 rounded-lg flex items-center justify-center text-slate-400 hover:text-blue-600 shadow-sm"
