            </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default SuperAdminView;

import React, { useState, useMemo, useEffect } from 'react';
import { Property, Bill, BillStatus, AuditLog, BillType } from '../types';
import { api } from '../services/api';

interface SuperAdminViewProps {
  properties: Property[];
  bills: Bill[];
  onAddProperty: (name: string, address: string, activeBillTypeIds: string[]) => void;
  auditLogs: AuditLog[];
  user: any;
}

const SuperAdminView: React.FC<SuperAdminViewProps> = ({ properties: initialProps, bills: initialBills, onAddProperty, auditLogs, user }) => {
  const [activeTab, setActiveTab] = useState<'PORTFOLIO' | 'AUDIT' | 'CONFIG'>('PORTFOLIO');
  const [billTypes, setBillTypes] = useState<BillType[]>([]);
  const [properties, setProperties] = useState<Property[]>(initialProps);
  const [bills, setBills] = useState<Bill[]>(initialBills);
  const [showAddProp, setShowAddProp] = useState(false);
  const [configPropId, setConfigPropId] = useState<string | null>(null);
  const [viewingPropId, setViewingPropId] = useState<string | null>(null);

  // Bill Dictionary State
  const [editingBillType, setEditingBillType] = useState<Partial<BillType> | null>(null);
  const [showBillTypeModal, setShowBillTypeModal] = useState(false);

  // New Property State
  const [selectedBillTypeIds, setSelectedBillTypeIds] = useState<string[]>([]);

  useEffect(() => {
    api.getBillTypes().then(setBillTypes);
  }, []);

  useEffect(() => {
    setProperties(initialProps);
  }, [initialProps]);

  useEffect(() => {
    setBills(initialBills);
  }, [initialBills]);

  const handleToggleBillForProp = async (propId: string, billTypeId: string) => {
    const prop = properties.find(p => p.id === propId);
    if (!prop) return;
    const current = prop.activeBillTypeIds;
    const updated = current.includes(billTypeId) 
      ? current.filter(id => id !== billTypeId) 
      : [...current, billTypeId];

    const updatedProps = await api.updatePropertyConfig(user, propId, updated);
    setProperties(updatedProps);
  };

  const handleSaveBillType = async (e: React.FormEvent) => {
    e.preventDefault();
    if (editingBillType) {
      const updatedTypes = await api.upsertBillType(user, editingBillType);
      setBillTypes(updatedTypes);
      setShowBillTypeModal(false);
      setEditingBillType(null);
    }
  };

  const handleDeleteBillType = async (id: string) => {
    if (confirm('Deleting this utility will remove it from all properties and existing history. Continue?')) {
      const updatedTypes = await api.deleteBillType(user, id);
      setBillTypes(updatedTypes);
      const updatedProps = await api.getProperties();
      setProperties(updatedProps);
    }
  };

  const handleAddPropSubmit = (e: React.FormEvent<HTMLFormElement>) => {
    e.preventDefault();
    const d = new FormData(e.currentTarget);
    const name = d.get('name') as string;
    const address = d.get('address') as string;

    if (!name || !address) return;

    onAddProperty(name, address, selectedBillTypeIds);
    setShowAddProp(false);
    setSelectedBillTypeIds([]);
  };

  const toggleBillSelection = (id: string) => {
    setSelectedBillTypeIds(prev => 
      prev.includes(id) ? prev.filter(i => i !== id) : [...prev, id]
    );
  };

  // Matrix Logic: Property History
  const historyMatrix = useMemo(() => {
    if (!viewingPropId) return null;
    const prop = properties.find(p => p.id === viewingPropId);
    if (!prop) return null;

    // Get all bill types that have ever existed for this property OR are currently active
    const activeBTs = billTypes.filter(bt => prop.activeBillTypeIds.includes(bt.id));
    const propBills = bills.filter(b => b.propertyId === viewingPropId);

    // Get unique months from bills
    const uniqueMonths = Array.from(new Set(propBills.map(b => b.month)));
    uniqueMonths.sort((a, b) => new Date(b).getTime() - new Date(a).getTime());

    return {
      property: prop,
      headers: activeBTs,
      rows: uniqueMonths.map(month => {
        return {
          month,
          statuses: activeBTs.map(bt => {
            const bill = propBills.find(b => b.month === month && b.billTypeId === bt.id);
            return bill ? bill.status : 'PENDING';
          })
        };
      })
    };
  }, [viewingPropId, properties, bills, billTypes]);

  return (
    <div className="max-w-6xl mx-auto space-y-6 animate-fadeIn pb-20">
      <div className="flex flex-wrap gap-2 p-1 bg-slate-200/50 rounded-2xl w-fit">
        {['PORTFOLIO', 'AUDIT', 'CONFIG'].map(tab => (
          <button 
            key={tab}
            onClick={() => setActiveTab(tab as any)}
            className={`px-6 py-2 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all ${
              activeTab === tab ? 'bg-white shadow-sm text-slate-900' : 'text-slate-500 hover:bg-slate-200'
            }`}
          >
            {tab}
          </button>
        ))}
      </div>

      {activeTab === 'PORTFOLIO' && (
        <div className="space-y-6">
          <div className="grid grid-cols-1 sm:grid-cols-3 gap-4">
            <div className="bg-white p-6 rounded-[2rem] border border-slate-100 shadow-sm">
              <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1">Assets</p>
              <p className="text-3xl font-black text-slate-800">{properties.length}</p>
            </div>
            <div className="bg-white p-6 rounded-[2rem] border border-slate-100 shadow-sm">
              <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1">Active Utilities</p>
              <p className="text-3xl font-black text-blue-600">{billTypes.length}</p>
            </div>
            <button 
              onClick={() => {
                setSelectedBillTypeIds([]);
                setShowAddProp(true);
              }}
              className="bg-slate-900 text-white rounded-[2rem] p-6 font-black uppercase text-xs tracking-widest hover:bg-black transition-all"
            >
              Add New Property
            </button>
          </div>

          <div className="bg-white rounded-[2.5rem] border border-slate-100 shadow-xl overflow-hidden">
            <table className="w-full text-left">
              <thead>
                <tr className="text-[10px] font-black text-slate-400 uppercase tracking-widest bg-slate-50/50">
                  <th className="px-8 py-5">Property</th>
                  <th className="px-8 py-5">Active Utilities</th>
                  <th className="px-8 py-5 text-right">Actions</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-slate-50">
                {properties.map(p => (
                  <tr key={p.id} className="hover:bg-slate-50 transition-all group">
                    <td 
                      className="px-8 py-6 cursor-pointer"
                      onClick={() => setViewingPropId(p.id)}
                    >
                      <div className="font-bold text-slate-800 group-hover:text-blue-600 transition-colors flex items-center gap-2">
                        {p.name}
                        <i className="fas fa-external-link-alt text-[10px] opacity-0 group-hover:opacity-100 transition-opacity"></i>
                      </div>
                      <div className="text-[9px] text-slate-400 font-bold uppercase">{p.address}</div>
                    </td>
                    <td className="px-8 py-6">
                      <div className="flex flex-wrap gap-2">
                        {p.activeBillTypeIds.map(btId => {
                          const bt = billTypes.find(t => t.id === btId);
                          return (
                            <span key={btId} className="px-2 py-1 bg-blue-50 text-blue-600 text-[8px] font-black rounded-lg uppercase flex items-center gap-1">
                              <i className={`fas ${bt?.icon || 'fa-bolt'} text-[10px]`}></i>
                              {bt?.name}
                            </span>
                          );
                        })}
                        {p.activeBillTypeIds.length === 0 && <span className="text-slate-300 italic text-[9px]">None configured</span>}
                      </div>
                    </td>
                    <td className="px-8 py-6 text-right">
                      <button 
                        onClick={() => setConfigPropId(p.id)}
                        className="text-slate-400 hover:text-blue-600 font-black uppercase text-[10px] tracking-widest bg-slate-50 px-4 py-2 rounded-xl transition-all"
                      >
                        Edit Config
                      </button>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </div>
      )}

      {/* PROPERTY BILL MATRIX MODAL (MONTHS VS UTILITIES) */}
      {viewingPropId && historyMatrix && (
        <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-md z-[250] flex items-center justify-center p-4">
          <div className="bg-white rounded-[3rem] shadow-2xl w-full max-w-5xl p-10 animate-scaleUp overflow-hidden flex flex-col max-h-[90vh]">
            <div className="flex justify-between items-start mb-8">
              <div>
                <h2 className="text-3xl font-black text-slate-800 leading-tight">Payment Matrix</h2>
                <div className="flex items-center gap-2 mt-1">
                  <p className="text-blue-600 text-[10px] font-black uppercase tracking-widest">{historyMatrix.property.name}</p>
