import React, { useState, useMemo, useEffect } from 'react';
import { Property, Bill, BillStatus, BillType } from '../types';
import { api } from '../services/api';

interface AdminViewProps {
  properties: Property[];
  bills: Bill[];
  onUpdateStatus: (billId: string, newStatus: BillStatus) => void;
  user: any;
}

const AdminView: React.FC<AdminViewProps> = ({ properties, bills, onUpdateStatus, user }) => {
  const [billTypes, setBillTypes] = useState<BillType[]>([]);
  const [showEntryPanel, setShowEntryPanel] = useState(false);
  const [activePropertyId, setActivePropertyId] = useState<string>(properties[0]?.id || '');

  const [entryBillTypeId, setEntryBillTypeId] = useState<string>('');
  const [entryPropertyId, setEntryPropertyId] = useState<string>('');

  useEffect(() => {
    api.getBillTypes().then(setBillTypes);
  }, []);

  const monthOptions = useMemo(() => {
    const months = [];
    const date = new Date();
    const monthNames = ["January", "February", "March", "April", "May", "June", "July", "August", "September", "October", "November", "December"];
    for (let i = 0; i < 6; i++) {
      const d = new Date(date.getFullYear(), date.getMonth() - i, 1);
      months.push(`${monthNames[d.getMonth()]} ${d.getFullYear()}`);
    }
    return months;
  }, []);

  const [selectedMonth, setSelectedMonth] = useState(monthOptions[0]);
  const isMonthEditable = monthOptions.slice(0, 3).includes(selectedMonth);

  const activeProperty = properties.find(p => p.id === activePropertyId);
  const entryBillType = billTypes.find(bt => bt.id === entryBillTypeId);

  useEffect(() => {
    if (showEntryPanel) {
      setEntryPropertyId(activePropertyId || properties[0]?.id || '');
    }
  }, [showEntryPanel, activePropertyId, properties]);

  useEffect(() => {
    if (entryPropertyId) {
      const prop = properties.find(p => p.id === entryPropertyId);
      if (prop && prop.activeBillTypeIds.length > 0) {
        setEntryBillTypeId(prop.activeBillTypeIds[0]);
      } else {
        setEntryBillTypeId('');
      }
    }
  }, [entryPropertyId, properties]);

  return (
    <div className="max-w-6xl mx-auto space-y-4 sm:space-y-6 animate-fadeIn pb-20">
      <div className="flex flex-col gap-4 bg-white p-5 sm:p-8 rounded-[1.5rem] sm:rounded-[2.5rem] shadow-sm border border-slate-100">
        <div className="space-y-1">
          <h1 className="text-2xl sm:text-3xl font-black text-slate-800 tracking-tight">Utility Hub</h1>
          <div className="flex items-center gap-2">
            <span className="text-slate-400 text-[10px] font-black uppercase tracking-widest">{selectedMonth}</span>
            {!isMonthEditable && <span className="bg-amber-50 text-amber-600 text-[8px] font-black px-2 py-0.5 rounded uppercase border border-amber-100">Locked</span>}
          </div>
        </div>

        <div className="flex flex-col sm:flex-row items-center gap-3 w-full">
          <select 
            value={selectedMonth}
            onChange={(e) => setSelectedMonth(e.target.value)}
            className="w-full sm:flex-1 px-4 py-3 bg-slate-50 border border-slate-100 rounded-xl sm:rounded-2xl font-black text-slate-700 outline-none text-[10px] sm:text-xs uppercase tracking-widest appearance-none"
          >
            {monthOptions.map(m => <option key={m} value={m}>{m}</option>)}
          </select>
          <button 
            onClick={() => setShowEntryPanel(true)}
            className="w-full sm:flex-1 bg-blue-600 text-white px-6 py-4 sm:py-3 rounded-xl sm:rounded-2xl font-black text-[10px] sm:text-xs uppercase tracking-widest shadow-xl shadow-blue-100 hover:bg-blue-700 active:scale-[0.98] transition-all"
          >
            New Entry
          </button>
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
        {/* Property Selector - Horizontal Scroll on Mobile */}
        <div className="bg-white p-5 sm:p-6 rounded-[1.5rem] sm:rounded-[2.5rem] border border-slate-100 shadow-sm space-y-3 sm:space-y-4">
          <h3 className="text-[10px] font-black text-slate-400 uppercase tracking-widest px-2">Managed Assets</h3>
          <div className="flex lg:flex-col overflow-x-auto lg:overflow-x-visible pb-2 lg:pb-0 gap-2 sm:gap-3 custom-scrollbar">
            {properties.map(p => (
              <button 
                key={p.id}
                onClick={() => setActivePropertyId(p.id)}
                className={`flex-shrink-0 lg:flex-shrink-1 w-[200px] lg:w-full p-4 sm:p-5 rounded-2xl sm:rounded-3xl text-left transition-all group ${
                  activePropertyId === p.id ? 'bg-slate-900 text-white shadow-xl' : 'bg-slate-50 lg:bg-transparent hover:bg-slate-100 text-slate-600'
                }`}
              >
                <div className="font-bold text-xs sm:text-sm truncate">{p.name}</div>
                <div className={`text-[8px] sm:text-[9px] uppercase font-black tracking-widest ${activePropertyId === p.id ? 'text-slate-400' : 'text-slate-300'}`}>
                  {p.activeBillTypeIds.length} Utilities
                </div>
              </button>
            ))}
          </div>
        </div>

        {/* Bill Utility List */}
        <div className="lg:col-span-2 space-y-4">
          <div className="bg-white rounded-[1.5rem] sm:rounded-[2.5rem] border border-slate-100 shadow-xl overflow-hidden">
            <div className="p-5 sm:p-6 bg-slate-50/50 border-b border-slate-100 flex justify-between items-center">
              <h3 className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Payment Status</h3>
              <span className="text-[8px] sm:text-[9px] font-bold text-slate-400 truncate max-w-[150px]">{activeProperty?.name}</span>
            </div>
            <div className="divide-y divide-slate-50">
              {activeProperty?.activeBillTypeIds.map(btId => {
                const bt = billTypes.find(t => t.id === btId);
                const bill = bills.find(b => b.propertyId === activePropertyId && b.billTypeId === btId && b.month === selectedMonth);

                return (
                  <div key={btId} className="p-5 sm:p-8 flex flex-col sm:flex-row items-start sm:items-center justify-between gap-4 group hover:bg-slate-50/30 transition-all">
                    <div className="flex items-center gap-4 sm:gap-5 w-full">
                      <div className="w-12 h-12 sm:w-14 sm:h-14 bg-white rounded-xl sm:rounded-2xl flex-shrink-0 flex items-center justify-center text-lg text-blue-600 border border-slate-100 shadow-sm group-hover:scale-105 transition-transform">
                        <i className={`fas ${bt?.icon || 'fa-bolt'}`}></i>
                      </div>
                      <div className="flex-1 min-w-0">
                        <div className="font-black text-slate-800 text-base sm:text-lg leading-tight truncate">{bt?.name}</div>
                        <div className="flex flex-wrap items-center gap-2 mt-1">
                          {bill?.amount !== undefined && <span className="text-[10px] sm:text-xs font-bold text-slate-500">${bill.amount}</span>}
                          {bill?.attachmentName && <span className="text-[8px] sm:text-[9px] font-black text-blue-400 uppercase flex items-center gap-1">
                            <i className="fas fa-paperclip"></i> File Attached
                          </span>}
                          {!bill && <span className="text-[8px] sm:text-[9px] font-black text-slate-300 uppercase italic">Entry Pending</span>}
                        </div>
                      </div>
                    </div>

                    {bill ? (
                      <button 
                        disabled={!isMonthEditable}
                        onClick={() => onUpdateStatus(bill.id, bill.status === BillStatus.PAID ? BillStatus.UNPAID : BillStatus.PAID)}
                        className={`w-full sm:w-auto sm:min-w-[120px] py-3.5 sm:py-3 rounded-xl sm:rounded-2xl text-[10px] font-black uppercase tracking-widest transition-all ${
                          !isMonthEditable ? 'bg-slate-100 text-slate-300 border border-slate-100' :
                          bill.status === BillStatus.PAID ? 'bg-emerald-500 text-white shadow-lg shadow-emerald-100' : 'bg-rose-500 text-white shadow-lg shadow-rose-100'
                        }`}
                      >
                        {bill.status}
                      </button>
                    ) : (
                      <div className="w-full sm:w-auto text-center text-[9px] font-black text-slate-300 uppercase tracking-widest px-4 py-2 bg-slate-50 rounded-xl border border-slate-100">Pending</div>
                    )}
                  </div>
                );
              })}
            </div>
          </div>
        </div>
      </div>

      {/* New Entry Modal - Mobile Optimized */}
      {showEntryPanel && (
        <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-md z-[200] flex items-end sm:items-center justify-center p-0 sm:p-4">
          <div className="bg-white rounded-t-[2.5rem] sm:rounded-[3rem] shadow-2xl w-full max-w-lg p-6 sm:p-10 animate-slideUp sm:animate-scaleUp overflow-y-auto max-h-[95vh]">
            <div className="flex justify-between items-start mb-6">
              <div>
                <h2 className="text-2xl sm:text-3xl font-black text-slate-800">Bill Entry</h2>
                <p className="text-slate-400 text-[10px] font-bold uppercase tracking-widest">Field Data Entry</p>
              </div>
              <button onClick={() => setShowEntryPanel(false)} className="w-10 h-10 rounded-full bg-slate-100 flex items-center justify-center text-slate-400">
                <i className="fas fa-times"></i>
              </button>
            </div>

            <form onSubmit={async (e) => {
              e.preventDefault();
              const f = new FormData(e.currentTarget);
              const entry = {
                propertyId: f.get('propertyId') as string,
                billTypeId: f.get('billTypeId') as string,
                month: f.get('month') as string,
                amount: f.get('amount') ? Number(f.get('amount')) : undefined,
                attachmentName: (f.get('file') as File)?.name || undefined
              };
              await api.submitBillEntry(user, entry);
              setShowEntryPanel(false);
              window.location.reload();
            }} className="space-y-4 sm:space-y-6">

              <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
                <div className="space-y-1">
                  <label className="text-[9px] sm:text-[10px] font-black text-slate-400 uppercase px-2">Asset</label>
                  <select 
                    name="propertyId" 
                    required 
                    value={entryPropertyId}
                    onChange={(e) => setEntryPropertyId(e.target.value)}
                    className="w-full p-4 bg-slate-50 border border-slate-100 rounded-xl sm:rounded-2xl font-bold outline-none appearance-none"
                  >
                    {properties.map(p => <option key={p.id} value={p.id}>{p.name}</option>)}
                  </select>
                </div>
                <div className="space-y-1">
                  <label className="text-[9px] sm:text-[10px] font-black text-slate-400 uppercase px-2">Utility</label>
                  <select 
                    name="billTypeId" 
                    required 
                    value={entryBillTypeId}
                    onChange={(e) => setEntryBillTypeId(e.target.value)}
                    className="w-full p-4 bg-slate-50 border border-slate-100 rounded-xl sm:rounded-2xl font-bold outline-none appearance-none"
                  >
                    {properties.find(p => p.id === entryPropertyId)?.activeBillTypeIds.map(btId => {
                      const bt = billTypes.find(t => t.id === btId);
                      return <option key={btId} value={btId}>{bt?.name}</option>;
                    })}
                  </select>
                </div>
              </div>

              <div className="space-y-1">
                <label className="text-[9px] sm:text-[10px] font-black text-slate-400 uppercase px-2">Month</label>
                <select name="month" required className="w-full p-4 bg-slate-50 border border-slate-100 rounded-xl sm:rounded-2xl font-bold outline-none appearance-none">
                  {monthOptions.slice(0, 3).map(m => <option key={m} value={m}>{m}</option>)}
                </select>
              </div>

              {entryBillType?.requiresAmount && (
                <div className="space-y-1">
                  <label className="text-[9px] sm:text-[10px] font-black text-slate-400 uppercase px-2">Amount ($)</label>
                  <input name="amount" type="number" step="0.01" required className="w-full p-4 bg-slate-50 border border-slate-100 rounded-xl sm:rounded-2xl font-bold outline-none" placeholder="0.00" />
                </div>
              )}

              {entryBillType?.requiresAttachment && (
                <div className="space-y-1">
                  <label className="text-[9px] sm:text-[10px] font-black text-slate-400 uppercase px-2">Document Proof</label>
                  <div className="relative">
                    <input name="file" type="file" required className="hidden" id="file-upload" />
                    <label htmlFor="file-upload" className="flex items-center justify-center gap-3 p-6 sm:p-8 bg-slate-50 border-2 border-dashed border-slate-200 rounded-xl sm:rounded-2xl cursor-pointer hover:bg-blue-50 transition-all text-slate-400 hover:text-blue-600 font-bold text-xs uppercase">
                      <i className="fas fa-cloud-upload-alt text-xl sm:text-2xl"></i>
                      Select File
                    </label>
                  </div>
                </div>
              )}

              <div className="flex gap-3 pt-4">
                <button type="button" onClick={() => setShowEntryPanel(false)} className="flex-1 py-4 text-slate-400 font-black uppercase text-[10px] tracking-widest">Discard</button>
                <button type="submit" className="flex-2 py-4 bg-slate-900 text-white rounded-xl sm:rounded-2xl font-black uppercase text-[10px] tracking-widest shadow-xl">Submit</button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default AdminView;

import React, { useState, useMemo, useEffect } from 'react';
import { Property, Bill, BillStatus, AuditLog, BillType } from '../types';
import { api } from '../services/api';

interface SuperAdminViewProps {
  properties: Property[];
  bills: Bill[];
  onAddProperty: (name: string, address: string, activeBillTypeIds: string[]) => void;
  auditLogs: AuditLog[];
  user: any;
}

const SuperAdminView: React.FC<SuperAdminViewProps> = ({ properties: initialProps, bills: initialBills, onAddProperty, auditLogs, user }) => {
  const [activeTab, setActiveTab] = useState<'PORTFOLIO' | 'AUDIT' | 'CONFIG'>('PORTFOLIO');
  const [billTypes, setBillTypes] = useState<BillType[]>([]);
  const [properties, setProperties] = useState<Property[]>(initialProps);
  const [bills, setBills] = useState<Bill[]>(initialBills);
  const [showAddProp, setShowAddProp] = useState(false);
  const [configPropId, setConfigPropId] = useState<string | null>(null);
  const [viewingPropId, setViewingPropId] = useState<string | null>(null);

  const [editingBillType, setEditingBillType] = useState<Partial<BillType> | null>(null);
  const [showBillTypeModal, setShowBillTypeModal] = useState(false);
  const [selectedBillTypeIds, setSelectedBillTypeIds] = useState<string[]>([]);

  useEffect(() => {
    api.getBillTypes().then(setBillTypes);
  }, []);

  useEffect(() => {
    setProperties(initialProps);
  }, [initialProps]);

  useEffect(() => {
    setBills(initialBills);
  }, [initialBills]);

  const handleToggleBillForProp = async (propId: string, billTypeId: string) => {
    const prop = properties.find(p => p.id === propId);
    if (!prop) return;
    const current = prop.activeBillTypeIds;
    const updated = current.includes(billTypeId) 
      ? current.filter(id => id !== billTypeId) 
      : [...current, billTypeId];

    const updatedProps = await api.updatePropertyConfig(user, propId, updated);
    setProperties(updatedProps);
  };

  const handleSaveBillType = async (e: React.FormEvent) => {
    e.preventDefault();
    if (editingBillType) {
      const updatedTypes = await api.upsertBillType(user, editingBillType);
      setBillTypes(updatedTypes);
      setShowBillTypeModal(false);
      setEditingBillType(null);
    }
  };

  const handleDeleteBillType = async (id: string) => {
    if (confirm('Delete utility type? This action cannot be undone.')) {
      const updatedTypes = await api.deleteBillType(user, id);
      setBillTypes(updatedTypes);
      const updatedProps = await api.getProperties();
      setProperties(updatedProps);
    }
  };

  const handleAddPropSubmit = (e: React.FormEvent<HTMLFormElement>) => {
    e.preventDefault();
    const d = new FormData(e.currentTarget);
    const name = d.get('name') as string;
    const address = d.get('address') as string;
    if (!name || !address) return;
    onAddProperty(name, address, selectedBillTypeIds);
    setShowAddProp(false);
    setSelectedBillTypeIds([]);
  };

  const toggleBillSelection = (id: string) => {
    setSelectedBillTypeIds(prev => 
      prev.includes(id) ? prev.filter(i => i !== id) : [...prev, id]
    );
  };

  const historyMatrix = useMemo(() => {
    if (!viewingPropId) return null;
    const prop = properties.find(p => p.id === viewingPropId);
    if (!prop) return null;

    const activeBTs = billTypes.filter(bt => prop.activeBillTypeIds.includes(bt.id));
    const propBills = bills.filter(b => b.propertyId === viewingPropId);
    const uniqueMonths = Array.from(new Set(propBills.map(b => b.month)));
    uniqueMonths.sort((a, b) => new Date(b).getTime() - new Date(a).getTime());

    return {
      property: prop,
      headers: activeBTs,
      rows: uniqueMonths.map(month => ({
        month,
        statuses: activeBTs.map(bt => {
          const bill = propBills.find(b => b.month === month && b.billTypeId === bt.id);
          return bill ? bill.status : 'PENDING';
        })
      }))
    };
  }, [viewingPropId, properties, bills, billTypes]);

  return (
    <div className="max-w-6xl mx-auto space-y-4 sm:space-y-6 animate-fadeIn pb-20">
      {/* Scrollable Tabs for Mobile */}
      <div className="flex overflow-x-auto pb-1 sm:pb-0 gap-2 p-1 bg-slate-200/50 rounded-xl sm:rounded-2xl w-full sm:w-fit no-scrollbar">
        {['PORTFOLIO', 'AUDIT', 'CONFIG'].map(tab => (
          <button 
            key={tab}
            onClick={() => setActiveTab(tab as any)}
            className={`flex-shrink-0 px-5 sm:px-6 py-2 rounded-lg sm:rounded-xl text-[9px] sm:text-[10px] font-black uppercase tracking-widest transition-all ${
              activeTab === tab ? 'bg-white shadow-sm text-slate-900' : 'text-slate-500 hover:bg-slate-200'
            }`}
          >
            {tab}
          </button>
        ))}
      </div>

      {activeTab === 'PORTFOLIO' && (
        <div className="space-y-4 sm:space-y-6">
          <div className="grid grid-cols-2 sm:grid-cols-3 gap-3 sm:gap-4">
            <div className="bg-white p-4 sm:p-6 rounded-2xl sm:rounded-[2rem] border border-slate-100 shadow-sm">
              <p className="text-[8px] sm:text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1">Assets</p>
              <p className="text-xl sm:text-3xl font-black text-slate-800">{properties.length}</p>
            </div>
            <div className="bg-white p-4 sm:p-6 rounded-2xl sm:rounded-[2rem] border border-slate-100 shadow-sm">
              <p className="text-[8px] sm:text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1">Utilities</p>
              <p className="text-xl sm:text-3xl font-black text-blue-600">{billTypes.length}</p>
            </div>
            <button 
              onClick={() => { setSelectedBillTypeIds([]); setShowAddProp(true); }}
              className="col-span-2 sm:col-span-1 bg-slate-900 text-white rounded-2xl sm:rounded-[2rem] p-4 sm:p-6 font-black uppercase text-[10px] sm:text-xs tracking-widest hover:bg-black active:scale-[0.98] transition-all"
            >
              + Add Property
            </button>
          </div>

          <div className="bg-white rounded-2xl sm:rounded-[2.5rem] border border-slate-100 shadow-xl overflow-hidden">
            {/* Table for Desktop, Cards for Mobile */}
            <div className="hidden sm:block">
              <table className="w-full text-left">
                <thead>
                  <tr className="text-[10px] font-black text-slate-400 uppercase tracking-widest bg-slate-50/50">
                    <th className="px-8 py-5">Property</th>
                    <th className="px-8 py-5">Active Utilities</th>
                    <th className="px-8 py-5 text-right">Actions</th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-slate-50">
                  {properties.map(p => (
                    <tr key={p.id} className="hover:bg-slate-50 transition-all group">
                      <td className="px-8 py-6 cursor-pointer" onClick={() => setViewingPropId(p.id)}>
                        <div className="font-bold text-slate-800 group-hover:text-blue-600 transition-colors flex items-center gap-2 truncate max-w-xs">
                          {p.name} <i className="fas fa-history text-[8px] opacity-20"></i>
                        </div>
                        <div className="text-[9px] text-slate-400 font-bold uppercase truncate max-w-xs">{p.address}</div>
                      </td>
                      <td className="px-8 py-6">
                        <div className="flex flex-wrap gap-2">
                          {p.activeBillTypeIds.slice(0, 3).map(btId => {
                            const bt = billTypes.find(t => t.id === btId);
                            return <span key={btId} className="px-2 py-1 bg-blue-50 text-blue-600 text-[8px] font-black rounded-lg uppercase">{bt?.name}</span>;
                          })}
                          {p.activeBillTypeIds.length > 3 && <span className="text-[8px] font-black text-slate-300">+{p.activeBillTypeIds.length - 3} more</span>}
                        </div>
                      </td>
                      <td className="px-8 py-6 text-right">
                        <button onClick={() => setConfigPropId(p.id)} className="text-[9px] font-black text-slate-400 uppercase tracking-widest bg-slate-50 px-3 py-1.5 rounded-lg">Config</button>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>

            {/* Mobile Property List */}
            <div className="sm:hidden divide-y divide-slate-50">
              {properties.map(p => (
                <div key={p.id} className="p-5 space-y-3">
                  <div className="flex justify-between items-start">
                    <div onClick={() => setViewingPropId(p.id)} className="flex-1">
                      <div className="font-black text-slate-800 text-sm flex items-center gap-2">
                        {p.name} <i className="fas fa-history text-[10px] text-blue-500"></i>
                      </div>
                      <div className="text-[9px] text-slate-400 font-bold uppercase truncate mt-0.5">{p.address}</div>
                    </div>
                    <button onClick={() => setConfigPropId(p.id)} className="w-8 h-8 rounded-lg bg-slate-50 flex items-center justify-center text-slate-400">
                      <i className="fas fa-cog"></i>
                    </button>
                  </div>
                  <div className="flex flex-wrap gap-2">
                    {p.activeBillTypeIds.map(btId => {
                      const bt = billTypes.find(t => t.id === btId);
                      return <span key={btId} className="px-2 py-1 bg-blue-50 text-blue-600 text-[8px] font-black rounded-lg uppercase">{bt?.name}</span>;
                    })}
                  </div>
                </div>
              ))}
            </div>
          </div>
        </div>
      )}

      {/* MATRIX MODAL - FULL SCREEN MOBILE */}
      {viewingPropId && historyMatrix && (
        <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-md z-[250] flex items-end sm:items-center justify-center p-0 sm:p-4">
          <div className="bg-white rounded-t-[2rem] sm:rounded-[3rem] shadow-2xl w-full max-w-5xl p-6 sm:p-10 animate-slideUp sm:animate-scaleUp overflow-hidden flex flex-col max-h-[98vh] sm:max-h-[90vh]">
            <div className="flex justify-between items-start mb-6 sm:mb-8">
              <div className="min-w-0">
                <h2 className="text-xl sm:text-3xl font-black text-slate-800 leading-tight truncate">History Matrix</h2>
                <div className="flex flex-wrap items-center gap-2 mt-1">
                  <p className="text-blue-600 text-[8px] sm:text-[10px] font-black uppercase tracking-widest truncate">{historyMatrix.property.name}</p>
                  <span className="hidden xs:inline w-1 h-1 bg-slate-300 rounded-full"></span>
                  <p className="hidden xs:block text-slate-400 text-[8px] sm:text-[10px] font-bold uppercase tracking-widest truncate">{historyMatrix.property.address}</p>
                </div>
              </div>
              <button onClick={() => setViewingPropId(null)} className="w-10 h-10 sm:w-12 sm:h-12 rounded-xl sm:rounded-2xl bg-slate-50 flex items-center justify-center text-slate-400">
                <i className="fas fa-times text-lg"></i>
              </button>
            </div>

            <div className="flex-1 overflow-auto border border-slate-100 rounded-xl sm:rounded-[2rem] bg-slate-50/30 custom-scrollbar">
              <table className="w-full border-collapse">
                <thead className="sticky top-0 z-20">
                  <tr className="bg-slate-100/90 backdrop-blur-md">
                    <th className="p-4 sm:p-6 text-left border-b border-r border-slate-200 min-w-[120px] sm:min-w-[180px] sticky left-0 z-30 bg-slate-100">
                      <span className="text-[8px] sm:text-[10px] font-black text-slate-400 uppercase tracking-widest">Billing Month</span>
                    </th>
                    {historyMatrix.headers.map(bt => (
                      <th key={bt.id} className="p-4 sm:p-6 text-center border-b border-slate-200 min-w-[100px]">
                        <div className="flex flex-col items-center gap-1 sm:gap-2">
                          <i className={`fas ${bt.icon} text-blue-500 text-xs sm:text-base`}></i>
                          <span className="text-[8px] sm:text-[10px] font-black text-slate-600 uppercase truncate max-w-[80px]">{bt.name}</span>
                        </div>
                      </th>
                    ))}
                  </tr>
                </thead>
                <tbody className="bg-white">
                  {historyMatrix.rows.map((row) => (
                    <tr key={row.month} className="hover:bg-blue-50/30 transition-colors">
                      <td className="p-4 sm:p-6 border-b border-r border-slate-100 sticky left-0 z-10 bg-white group-hover:bg-blue-50/30">
                        <span className="font-black text-slate-800 text-xs sm:text-sm">{row.month}</span>
                      </td>
                      {row.statuses.map((status, sIdx) => (
                        <td key={sIdx} className="p-4 sm:p-6 text-center border-b border-slate-100">
                          <div className="flex justify-center">
                            {status === 'PAID' ? (
                              <div className="w-8 h-8 sm:w-10 sm:h-10 bg-emerald-50 rounded-full flex items-center justify-center text-emerald-500 border border-emerald-100">
                                <i className="fas fa-check text-xs sm:text-base"></i>
                              </div>
                            ) : status === 'UNPAID' ? (
                              <div className="w-8 h-8 sm:w-10 sm:h-10 bg-rose-50 rounded-full flex items-center justify-center text-rose-500 border border-rose-100">
                                <i className="fas fa-times text-xs sm:text-base"></i>
                              </div>
                            ) : (
                              <div className="w-8 h-8 sm:w-10 sm:h-10 bg-slate-50 rounded-full flex items-center justify-center text-slate-300">
                                <i className="fas fa-minus text-[10px]"></i>
                              </div>
                            )}
                          </div>
                        </td>
                      ))}
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>

            <div className="mt-6 sm:mt-8 flex flex-col sm:flex-row justify-between items-center gap-4">
               <div className="flex gap-4">
                  <div className="flex items-center gap-1.5"><div className="w-2 h-2 rounded-full bg-emerald-500"></div><span className="text-[8px] font-black text-slate-400 uppercase">Paid</span></div>
                  <div className="flex items-center gap-1.5"><div className="w-2 h-2 rounded-full bg-rose-500"></div><span className="text-[8px] font-black text-slate-400 uppercase">Due</span></div>
                  <div className="flex items-center gap-1.5"><div className="w-2 h-2 rounded-full bg-slate-300"></div><span className="text-[8px] font-black text-slate-400 uppercase">Empty</span></div>
