               <button onClick={() => setViewingPropId(null)} className="w-full sm:w-auto px-10 py-4 bg-slate-900 text-white rounded-xl sm:rounded-2xl font-black uppercase text-[10px] tracking-widest shadow-xl">Close</button>
            </div>
          </div>
        </div>
      )}

