              <input required className="w-full p-4 bg-slate-50 border border-slate-100 rounded-xl sm:rounded-2xl font-bold outline-none" value={editingBillType?.icon || ''} onChange={e => setEditingBillType({ ...editingBillType!, icon: e.target.value })} placeholder="Icon (e.g., fa-bolt)" />
