import { api } from '../services/api';

interface SuperAdminViewProps {
  properties: Property[];
  bills: Bill[];
  onAddProperty: (name: string, address: string, cityId: string, activeBillTypeIds: string[]) => void;
  auditLogs: AuditLog[];
  user: any;
